// ── RECOMMENDATION POOL ──────────────────────────────────────────────────────
// ~500 curated recommendations, each tagged by:
//   e  = energy level  : 'depleted' | 'low' | 'medium' | 'high'
//   a  = neglected area: 'health' | 'work' | 'learning' | 'relationships' | 'mindfulness' | 'creativity'
//   t  = time slots    : array of 'LN'(22-5) | 'EM'(5-8) | 'MO'(8-12) | 'MD'(12-14) | 'AF'(14-17) | 'EV'(17-20) | 'NI'(20-22)
//   w  = weather pref  : 'any' | 'in' (bad weather) | 'out' (good weather)
//   mins = duration in minutes
//   label = short card title (3-5 words)
//   text  = full warm coaching text (40-65 words)
//
// Selection logic lives in ai.js → getLocalRec()
// Claude API replaces this pool in the next phase.

const REC_POOL = [

  // ══════════════════════════════════════════════════════════════════════════
  // HEALTH
  // ══════════════════════════════════════════════════════════════════════════

  // ── HEALTH · DEPLETED ────────────────────────────────────────────────────
  {e:'depleted',a:'health',t:['LN','EM','MO','MD','AF','EV','NI'],w:'any',mins:3,label:'Box breathing',text:"Sit wherever you are and try 3 minutes of box breathing — inhale 4 counts, hold 4, exhale 4, hold 4. That's genuinely enough for now. This single exercise shifts your nervous system out of stress mode without asking anything of your body."},
  {e:'depleted',a:'health',t:['LN','EM','MO','MD','AF','EV','NI'],w:'any',mins:5,label:'Drink water slowly',text:"Go get a full glass of water and drink it slowly over 5 minutes. Sit down while you do it. Dehydration is one of the most common causes of that heavy, foggy, can't-function feeling. This tiny act might be exactly what your body needs right now."},
  {e:'depleted',a:'health',t:['LN','EM','MO','MD','AF','EV','NI'],w:'any',mins:5,label:'Gentle neck rolls',text:"Drop your chin slowly to your chest and roll your head in gentle circles — left ear to shoulder, back, right ear to shoulder, forward. Do it for 5 minutes at whatever speed feels comfortable. Your neck holds more tension than you realise."},
  {e:'depleted',a:'health',t:['EV','NI','LN'],w:'any',mins:5,label:'Legs up the wall',text:"Lie on your back and slide your legs straight up the wall. Stay for 5 minutes with your arms relaxed at your sides. This inversion improves circulation, calms the nervous system, and requires absolutely zero effort. Let gravity do all the work."},
  {e:'depleted',a:'health',t:['EM','MO'],w:'out',mins:5,label:'Sit in morning sun',text:"Step outside and sit in the sunlight for 5 minutes. Don't scroll, don't plan. Morning light regulates your body clock and can lift energy more gently than a second coffee. Close your eyes and let the warmth land on your face."},
  {e:'depleted',a:'health',t:['EV','NI','LN'],w:'any',mins:7,label:'Herbal tea ritual',text:"Put the kettle on and make yourself a cup of herbal tea. Sit with it somewhere quiet for 7 minutes without your phone. Let the warmth and the pause be enough. When you're running on empty, deliberately slowing down is the most productive move."},
  {e:'depleted',a:'health',t:['EM','LN'],w:'any',mins:5,label:'Stretch in bed',text:"Before you get up or before you try to sleep, spend 5 minutes stretching gently in bed — arms overhead, knees hugged to your chest, slow spinal twist each side. No mat, no effort, no excuses needed. Your body will feel the difference."},
  {e:'depleted',a:'health',t:['LN','NI','EV'],w:'any',mins:5,label:'Body scan rest',text:"Lie down and close your eyes. Slowly move your attention from your toes up to your head, noticing each area without trying to change anything. This is one of the most restorative things you can do when depleted — and it requires nothing from you."},
  {e:'depleted',a:'health',t:['MO','MD','AF'],w:'any',mins:5,label:'Eat something real',text:"Take 5 minutes to eat something genuinely nutritious — a banana, nuts, yogurt, anything whole. Blood sugar crashes are often disguised as exhaustion. Sit down to eat it, without a screen. Small thing, real impact on how you'll feel in 20 minutes."},
  {e:'depleted',a:'health',t:['LN','NI'],w:'any',mins:0,label:'Go to sleep now',text:"Your body is giving you a clear signal. The single best health investment you can make right now is sleep. Put your phone down, dim the lights, and give yourself permission to stop completely. Everything else genuinely can wait until tomorrow."},

  // ── HEALTH · LOW ─────────────────────────────────────────────────────────
  {e:'low',a:'health',t:['MO','AF','EV'],w:'out',mins:15,label:'Slow walk outside',text:"Lace up and take a slow 15-minute walk outside with no pace target and no destination pressure. Low energy often lifts naturally after the first 5 minutes of gentle movement. Let the walk be whatever it needs to be — not exercise, just motion."},
  {e:'low',a:'health',t:['MO','MD','AF','EV','NI'],w:'in',mins:15,label:'Gentle yoga flow',text:"Roll out a mat or clear some floor space and do 15 minutes of gentle yoga. Child's pose, cat-cow, a few slow sun salutations at your own pace. The weather outside doesn't matter at all — this is entirely yours to take at whatever speed feels right."},
  {e:'low',a:'health',t:['MO','AF'],w:'any',mins:20,label:'Light swim session',text:"Head to a pool for a relaxed 20-minute swim. Don't time your laps or push the pace — just move through water at whatever rhythm feels good. Swimming is uniquely restorative at low energy because the buoyancy carries your weight while you move."},
  {e:'low',a:'health',t:['MD','EV'],w:'any',mins:20,label:'Cook a nourishing meal',text:"Spend 20 minutes cooking yourself something genuinely good. A proper meal, made with care, signals to your body that you're worth looking after. Put on music, chop slowly, and enjoy the process rather than rushing towards the result."},
  {e:'low',a:'health',t:['MO','AF'],w:'out',mins:15,label:'Easy cycle ride',text:"Take a gentle 15-minute bike ride at a comfortable pace. The goal isn't distance — it's fresh air, light movement, and a break from stillness. Even a slow loop around the neighbourhood activates your lymphatic system and shakes off mental fog."},
  {e:'low',a:'health',t:['MO','MD','AF','EV'],w:'any',mins:10,label:'Foam rolling session',text:"Spend 10 minutes with a foam roller on your back, legs, and hips. Go slowly over tight spots — this is recovery work disguised as effort. Your body will feel measurably looser and your energy slightly higher by the time you finish."},
  {e:'low',a:'health',t:['MO','MD','AF'],w:'in',mins:20,label:'Bodyweight circuit',text:"Do a simple 20-minute bodyweight circuit at home — 10 squats, 8 push-ups, 15 sit-ups, repeat. No equipment, no gym required. Modify every exercise to whatever your body can actually manage today. Starting is the whole battle."},
  {e:'low',a:'health',t:['EM'],w:'any',mins:10,label:'Contrast shower',text:"Take a 10-minute shower alternating between warm and cool water for 30-second intervals. It sounds harsh but the contrast improves circulation and mentally signals a fresh start to the hour. End with 10 seconds of cold if you can manage it."},
  {e:'low',a:'health',t:['MO','MD'],w:'out',mins:15,label:'Walk with a purpose',text:"Walk somewhere nearby with a small purpose — a café, a shop, a park bench. Having a destination makes 15 minutes of walking feel intentional rather than like exercise. The movement and the fresh air count equally, regardless of your destination."},
  {e:'low',a:'health',t:['EV','NI'],w:'any',mins:15,label:'Prep tomorrow\'s food',text:"Spend 15 minutes prepping something for tomorrow — soaked oats, chopped veg, a marinated protein. Investing in tomorrow's nutrition when energy is low costs you almost nothing tonight but pays back significantly when tomorrow's busy."},
  {e:'low',a:'health',t:['MO','MD','AF','EV'],w:'in',mins:15,label:'Light pilates',text:"Follow a 15-minute beginner pilates video — search for one on YouTube and just press play. Pilates is especially good at low energy because it works deep stabilising muscles without taxing your cardiovascular system or requiring any equipment."},
  {e:'low',a:'health',t:['AF','EV'],w:'out',mins:20,label:'Afternoon walk',text:"Step outside for a 20-minute afternoon stroll. Research shows a short walk after 3pm measurably improves sleep quality that night. You're investing in tonight's rest as much as today's health by stepping outside right now."},
  {e:'low',a:'health',t:['NI','LN'],w:'any',mins:10,label:'Wind-down stretch',text:"Spend 10 minutes in a gentle wind-down stretch before sleep — legs up the wall, happy baby pose, a slow spinal twist each side. This moves your body from waking mode to recovery mode far more effectively than another 10 minutes of scrolling."},
  {e:'low',a:'health',t:['MO','MD','AF'],w:'any',mins:15,label:'Full-body stretching',text:"Spend 15 minutes on a proper full-body stretch — hamstrings, hip flexors, chest, shoulders, spine in both directions. Put on a guided video if you need the structure. Flexibility work is almost always the most neglected part of a health routine."},
  {e:'low',a:'health',t:['MO','AF'],w:'in',mins:15,label:'Indoor dance break',text:"Close your door, put on a playlist you actually like, and move freely for 15 minutes. It doesn't need to look like anything. The combination of music, movement, and a rare moment of silliness does more for low energy than almost any structured workout."},
  {e:'low',a:'health',t:['MO','MD'],w:'any',mins:5,label:'Set hydration reminders',text:"Set a phone reminder to drink water every 90 minutes for the rest of today, then drink a glass right now. Mild dehydration consistently mimics the symptoms of low energy. It's one of the easiest health fixes there is and almost no one does it."},
  {e:'low',a:'health',t:['MO','AF'],w:'out',mins:20,label:'Walk in nature',text:"Find the nearest park or green space and walk slowly through it for 20 minutes. Research is remarkably consistent: time in nature lowers cortisol, improves mood, and reduces the perception of fatigue — even a small urban park counts."},
  {e:'low',a:'health',t:['EV','NI'],w:'any',mins:10,label:'Breathing before bed',text:"Lie in bed and do 10 minutes of slow breathing — 5 counts in, 5 counts out. Let your exhale be slightly longer than your inhale. This activates your parasympathetic nervous system and is one of the most evidence-backed ways to improve sleep quality."},
  {e:'low',a:'health',t:['MO','MD','AF'],w:'any',mins:20,label:'Healthy grocery run',text:"Walk or drive to the shops and pick up 5-7 genuinely nutritious foods for the week. Having good food available removes the decision fatigue that makes healthy eating hard. Spend 20 minutes and set yourself up properly."},
  {e:'low',a:'health',t:['MO','AF'],w:'any',mins:10,label:'10-min beginner yoga',text:"Do a 10-minute beginner yoga session — just search 'ten minute morning yoga' and pick the first result. This is accessible at any flexibility level and leaves most people feeling better than before, every single time."},

  // ── HEALTH · MEDIUM ──────────────────────────────────────────────────────
  {e:'medium',a:'health',t:['MO','AF'],w:'out',mins:30,label:'Brisk walk or jog',text:"Head out for a 30-minute brisk walk or light jog. Find a rhythm that lets you hold a short conversation — not gasping, not strolling. This intensity has the strongest evidence base for improving mood, cardiovascular health, and sustained energy."},
  {e:'medium',a:'health',t:['MO','MD','AF'],w:'any',mins:45,label:'Gym session',text:"Get yourself to the gym for 45 minutes. Stick to compound movements — squat, press, pull, hinge. You don't need a complex program today; just show up, move weight, and leave stronger than you arrived. Consistency matters far more than perfection."},
  {e:'medium',a:'health',t:['MO','AF'],w:'in',mins:30,label:'Home HIIT workout',text:"Do a 30-minute HIIT session at home — 40 seconds on, 20 seconds off across burpees, mountain climbers, jump squats, and push-ups. No equipment, high return. The rain outside is irrelevant. Your living room is enough."},
  {e:'medium',a:'health',t:['MO','MD','AF','EV'],w:'any',mins:25,label:'Intermediate yoga',text:"Roll out your mat for a 25-minute intermediate yoga flow. Move with your breath, hold poses a beat longer than comfortable, and finish with 5 minutes of savasana. This is complete body-mind maintenance in under 30 minutes."},
  {e:'medium',a:'health',t:['LN','NI'],w:'any',mins:5,label:'Sleep — it\'s late',text:"It's late and your energy is medium — which means your body has been running on reserves all day. The highest-return health investment right now is sleep. Put your phone face-down, close your eyes, and let recovery begin."},
  {e:'medium',a:'health',t:['MO','AF'],w:'out',mins:30,label:'Outdoor cycle',text:"Take your bike out for a 30-minute ride at a steady pace. Cycling outside combines cardiovascular benefit with mental decompression in a way that indoor alternatives genuinely can't match. Set a comfortable but purposeful pace."},
  {e:'medium',a:'health',t:['MD'],w:'any',mins:20,label:'Midday movement break',text:"Step away from whatever you're doing for a 20-minute movement break. Walk, do bodyweight exercises, or stretch — just get blood moving before the post-lunch energy dip arrives. Prevention is far easier than fighting the dip once it lands."},
  {e:'medium',a:'health',t:['MO','AF'],w:'any',mins:30,label:'Swimming session',text:"Spend 30 minutes at the pool swimming laps at a comfortable pace. Swimming simultaneously builds strength, cardio capacity, and flexibility — and the meditative rhythm of the water is genuinely difficult to replicate in any other form of exercise."},
  {e:'medium',a:'health',t:['EV'],w:'any',mins:25,label:'Evening run',text:"Lace up for a 25-minute evening run at a comfortable pace — this is maintenance work, not a race. Aim to finish before 8pm to give your nervous system enough time to wind down before it's time to sleep."},
  {e:'medium',a:'health',t:['MO','MD','AF'],w:'any',mins:35,label:'Focused strength session',text:"Do a 35-minute strength session focusing on one or two major muscle groups. Choose 4-5 exercises, 3-4 sets each, and rest properly between sets. Quality movement over rushed reps — every single time."},
  {e:'medium',a:'health',t:['MO','AF'],w:'out',mins:45,label:'Hike or trail walk',text:"Find a trail or park and spend 45 minutes hiking at a moderate pace. Uneven terrain activates muscles that flat surfaces never touch, and time in nature measurably lowers cortisol. This is genuinely dual-purpose health work."},
  {e:'medium',a:'health',t:['MO','MD','AF'],w:'any',mins:20,label:'Structured meal prep',text:"Spend 20 minutes on meal prep with a plan — batch cook a grain, prepare a protein, chop vegetables for three days ahead. Eating well when life gets busy isn't about willpower; it's about having done the work before it got busy."},
  {e:'medium',a:'health',t:['MO','AF'],w:'in',mins:30,label:'Dance cardio session',text:"Put on a playlist you love and do 30 minutes of dance-based cardio. Follow a YouTube video or go freestyle — both are equally valid. It should feel slightly ridiculous. That's how you know it's working."},
  {e:'medium',a:'health',t:['NI','EV'],w:'any',mins:20,label:'Recovery and mobility',text:"Spend 20 minutes on intentional recovery — foam rolling, dynamic stretching, and 5 minutes of box breathing. Done consistently, recovery work is what makes harder sessions sustainable week after week without accumulating injury."},
  {e:'medium',a:'health',t:['MO','AF'],w:'out',mins:20,label:'Outdoor bodyweight circuit',text:"Find a park and do a 20-minute outdoor bodyweight circuit — use a bench for step-ups and dips, the grass for push-ups and squats. Moving in fresh air with actual sunlight is meaningfully different from moving inside."},
  {e:'medium',a:'health',t:['EM','MO'],w:'any',mins:20,label:'Morning mobility routine',text:"Start your day with 20 minutes of joint mobility work — hip circles, shoulder rotations, spinal waves, ankle alphabets. This kind of maintenance work accumulates massive long-term value while feeling almost effortless in the moment."},
  {e:'medium',a:'health',t:['MO','MD','AF'],w:'any',mins:30,label:'Sport or recreational activity',text:"Play a sport or do a recreational activity you genuinely enjoy — tennis, basketball, a kick-about in the park. Medium energy is the sweet spot for recreational sport because you can perform well without the risk of overdoing it."},
  {e:'medium',a:'health',t:['MO','AF'],w:'in',mins:40,label:'At-home full workout',text:"Do a complete 40-minute workout at home with a proper warm-up, main session, and cool-down. No equipment needed — just floor space and the intent to see it through. Structure the session like you would at a gym: progressive, intentional, complete."},

  // ── HEALTH · HIGH ────────────────────────────────────────────────────────
  {e:'high',a:'health',t:['MO','AF'],w:'out',mins:45,label:'Long run',text:"Your energy is high — use it with purpose. Lace up and go for a 45-minute run at a genuinely challenging pace. Pick a route with some incline. Push beyond your comfortable distance. High energy days are exactly when you build real fitness."},
  {e:'high',a:'health',t:['MO','AF'],w:'any',mins:60,label:'Heavy gym session',text:"Get to the gym and make every minute count — 60 minutes of compound lifts with progressive overload. Track your weights, beat last week's numbers where possible, and leave having genuinely challenged yourself. High energy is currency; spend it wisely."},
  {e:'high',a:'health',t:['MO','AF'],w:'out',mins:60,label:'Sport or fitness class',text:"Sign up for or attend a sport, fitness class, or group outdoor activity — climbing, football, tennis, CrossFit, whatever gets you competing or moving with others. High energy is wasted on solo gentle exercise. Find something that pushes back."},
  {e:'high',a:'health',t:['MO','MD','AF'],w:'any',mins:45,label:'Intense home workout',text:"Do an intense 45-minute home workout — tabata intervals, plyometric circuits, progressive difficulty sets. Take only the rest the format demands. You have fuel; this is the time to burn it in a way that builds something real."},
  {e:'high',a:'health',t:['MO','AF'],w:'out',mins:60,label:'Long ride or trail run',text:"Take a long bike ride or trail run — 60 minutes at a sustained, challenging effort. Push your cardiovascular system while your energy fully supports it. Sessions like this, done well, are the ones that move your baseline fitness."},
  {e:'high',a:'health',t:['MO','MD','AF','EV'],w:'any',mins:60,label:'Complete training block',text:"Run a complete 60-minute training block — structured warm-up, main session across multiple movement patterns, proper cool-down, 10 minutes of flexibility work at the end. Don't shortcut the recovery portion just because you feel strong."},
  {e:'high',a:'health',t:['LN','NI'],w:'any',mins:5,label:'Sleep for recovery',text:"Even at high energy, your body needs sleep to convert today's effort into tomorrow's strength. Recovery happens during rest, not during exercise. Wind down now — your gains are waiting on the other side of a good night's sleep."},
  {e:'high',a:'health',t:['MO','AF'],w:'out',mins:90,label:'Adventure activity',text:"Do something active outdoors that you genuinely enjoy and that takes real effort — a long hike, open water swimming, a climb, a long cycle through new terrain. High energy deserves a high-quality outlet. Make today a story worth telling."},
  {e:'high',a:'health',t:['MO','AF'],w:'any',mins:30,label:'Personal record attempt',text:"Choose one exercise you want to improve — a heavier lift, more consecutive push-ups, a faster sprint — and spend 30 focused minutes pursuing a personal record. High energy days are exactly when these attempts pay off most."},
  {e:'high',a:'health',t:['MO','MD','AF'],w:'any',mins:45,label:'Functional strength training',text:"Spend 45 minutes on functional fitness — farmer carries, kettlebell complexes, pull-ups, sled work if available. Train movements that translate directly to real-world capability. Your energy today can build strength that serves you for years."},

  // ══════════════════════════════════════════════════════════════════════════
  // WORK
  // ══════════════════════════════════════════════════════════════════════════

  // ── WORK · DEPLETED ──────────────────────────────────────────────────────
  {e:'depleted',a:'work',t:['MO','MD','AF','EV'],w:'any',mins:5,label:'Write 3 priorities',text:"Open a blank note and write down just three things that actually matter today — not your full task list, just three. Pick the smallest one and do only that. When depleted, one completed task beats ten started ones every single time."},
  {e:'depleted',a:'work',t:['MO','MD','AF'],w:'any',mins:5,label:'Clear your inbox',text:"Spend 5 minutes on your inbox — archive, delete, and flag. Don't write long replies. Just triage. A lighter inbox removes low-grade anxiety that drains energy you can't currently spare. Five minutes, then close it."},
  {e:'depleted',a:'work',t:['LN','NI'],w:'any',mins:5,label:'Tomorrow\'s one task',text:"Before you sleep, write down the single most important thing to do tomorrow and put it somewhere you'll see it. That's the whole task. Planning tomorrow with a clear mind — even depleted — saves 20 minutes of anxious morning scrambling."},
  {e:'depleted',a:'work',t:['MO','MD','AF'],w:'any',mins:10,label:'Voice memo brain dump',text:"Open your phone's voice recorder and speak out everything that's on your work mind for 10 minutes. Don't organise it — just talk. Getting it out of your head and into a recording reduces the cognitive load of holding it all mentally."},
  {e:'depleted',a:'work',t:['MO','MD','AF','EV'],w:'any',mins:5,label:'Decline one thing',text:"Look at your commitments for the next 48 hours and send one polite decline or postpone request. When energy is depleted, protecting what remains is more valuable than adding to the pile. One well-placed 'no' is productive work."},
  {e:'depleted',a:'work',t:['MO','MD','AF'],w:'any',mins:10,label:'Organise your workspace',text:"Spend 10 minutes tidying your physical workspace — clear desk, file one pile of papers, put away what doesn't belong. Environment affects cognition directly. A cleaner space will help your depleted brain work more efficiently."},
  {e:'depleted',a:'work',t:['MO','MD','AF'],w:'any',mins:5,label:'Update your task list',text:"Open your task manager or notebook and spend 5 minutes updating your task list — add anything new, strike off anything done, rearrange the order. Clear lists reduce the mental energy of remembering things you've already committed to."},
  {e:'depleted',a:'work',t:['MO','MD'],w:'any',mins:10,label:'One email response',text:"Pick the one email in your inbox that will have the most impact if replied to today and write a response — brief, direct, complete. Just one. Send it and close your email. You've done something real in 10 minutes."},
  {e:'depleted',a:'work',t:['LN','NI','EV'],w:'any',mins:5,label:'Plan tomorrow\'s schedule',text:"Block out tomorrow's calendar with 3-4 focused work sessions now, while you're depleted, so tomorrow's rested self doesn't have to think about when to do what. Five minutes of planning tonight saves 30 minutes of morning friction."},
  {e:'depleted',a:'work',t:['MO','MD','AF'],w:'any',mins:5,label:'One admin task',text:"Pick the simplest, most overdue admin task — an invoice, a form, a quick file organisation — and do it in 5 minutes. Depleted energy is sufficient for admin. Clearing these creates a surprising amount of background mental space."},

  // ── WORK · LOW ───────────────────────────────────────────────────────────
  {e:'low',a:'work',t:['MO','MD','AF'],w:'any',mins:20,label:'Focused deep work block',text:"Set a timer for 20 minutes, close everything irrelevant, and work on the single most important task without interruption. Low energy isn't an obstacle to a focused 20-minute block — it's exactly the right length. Stop when the timer ends."},
  {e:'low',a:'work',t:['MO'],w:'any',mins:15,label:'Plan your full day',text:"Spend 15 minutes at the start of the day building a realistic schedule — block time for your 3 priority tasks, include a proper break, and protect your best hours. Planning isn't procrastination; it's the reason the day won't slip away."},
  {e:'low',a:'work',t:['MO','MD','AF'],w:'any',mins:20,label:'Tackle email properly',text:"Spend 20 minutes on email with intention — write the replies that are actually overdue, archive the noise, and leave your inbox clean. Low energy is perfectly sufficient for this. Set a timer and close it when it rings."},
  {e:'low',a:'work',t:['MD','AF'],w:'any',mins:15,label:'Readable review session',text:"Spend 15 minutes reviewing documents, proposals, or reports you've been putting off. Reading is cognitively lighter than writing or deciding and is a productive way to use low-energy time without burning out on harder work."},
  {e:'low',a:'work',t:['MO','MD','AF'],w:'any',mins:20,label:'Complete one deliverable',text:"Pick one thing from your task list that you can complete fully in 20 minutes and do nothing else until it's done. Finishing something — even something small — creates momentum that low energy struggles to generate through quantity of tasks."},
  {e:'low',a:'work',t:['MO','AF'],w:'any',mins:15,label:'Update project notes',text:"Spend 15 minutes updating your notes on a key project — where it stands, what's next, what's blocked. Clear notes reduce the energy cost of re-orienting yourself every time you pick the project back up. Future you will be grateful."},
  {e:'low',a:'work',t:['MO','MD','AF'],w:'any',mins:20,label:'Follow up on blockers',text:"Identify the two things most blocking your work and send a brief follow-up message or make a quick call to unblock them. Removing obstacles is high-leverage work that requires less energy than the tasks the obstacles are blocking."},
  {e:'low',a:'work',t:['AF','EV'],w:'any',mins:15,label:'Weekly review',text:"Do a 15-minute weekly review — what did you complete this week, what slipped, what carries forward. The review itself is productive work that directly improves next week. Low energy is no barrier to reflection."},
  {e:'low',a:'work',t:['MO','MD','AF'],w:'any',mins:25,label:'Draft without editing',text:"Open a document and write a rough draft of something overdue — an email, a proposal, a report section — without stopping to edit. Let it be messy. A rough draft you can refine is infinitely more useful than a blank document you're waiting to feel ready for."},
  {e:'low',a:'work',t:['MO','MD'],w:'any',mins:15,label:'Admin and filing',text:"Spend 15 minutes on admin tasks — file documents, organise a shared drive, update a spreadsheet, tidy a shared tool. Low energy is more than enough for admin. Clearing the backlog creates real space for better work later."},
  {e:'low',a:'work',t:['MO','MD','AF'],w:'any',mins:20,label:'Prepare for tomorrow',text:"Spend 20 minutes preparing the materials, documents, or context you'll need for tomorrow's most important meeting or task. Tomorrow's you will be more focused and less scrambled if today's you did the preparation."},
  {e:'low',a:'work',t:['AF'],w:'any',mins:15,label:'Async communication sweep',text:"Spend 15 minutes responding to Slack messages, Teams threads, or other async communications you've left on read. Clear the queue. Even at low energy, brief direct responses move things forward and reduce the guilt of things outstanding."},
  {e:'low',a:'work',t:['MO','MD','AF'],w:'any',mins:20,label:'Research one topic',text:"Spend 20 minutes researching one topic relevant to your work — read two or three articles, make brief notes, add the useful links somewhere you'll find them. Low energy is actually good for reading and absorbing rather than producing."},
  {e:'low',a:'work',t:['MO','MD','AF'],w:'any',mins:15,label:'Tidy your workspace',text:"Spend 15 minutes organising your digital and physical workspace — clean up your desktop, file old documents, clear your desk. Environment has a direct, measurable effect on focus. A clear space is a legitimate productivity investment."},
  {e:'low',a:'work',t:['LN','NI'],w:'any',mins:10,label:'Shutdown ritual',text:"Do a proper work shutdown — close all work tabs, write tomorrow's top 3 tasks in your notebook, and set your laptop aside. A clean mental end to the workday measurably improves sleep quality and next-day readiness."},
  {e:'low',a:'work',t:['MO','MD','AF'],w:'any',mins:20,label:'Skill-adjacent reading',text:"Read for 20 minutes on a topic directly related to your work — industry news, a technical article, a case study. Staying current requires less energy than producing and compounds as professional knowledge over time."},
  {e:'low',a:'work',t:['MO','MD'],w:'any',mins:15,label:'Calendar audit',text:"Look at the next two weeks of your calendar and remove or reschedule anything that isn't necessary or isn't a good use of your time. Protecting your calendar is legitimate high-value work."},

  // ── WORK · MEDIUM ────────────────────────────────────────────────────────
  {e:'medium',a:'work',t:['MO','MD','AF'],w:'any',mins:45,label:'Deep work session',text:"Block 45 minutes of protected focus time on your most cognitively demanding task. Phone away, notifications off, one document open. Medium energy is the sweet spot for sustained deep work — enough to push hard without burning out before finishing."},
  {e:'medium',a:'work',t:['MO'],w:'any',mins:25,label:'Strategic day planning',text:"Spend 25 minutes doing a proper strategic plan for the day — time-block your priorities, identify the one task that would make the day a success if it's the only thing completed, and protect the best hours of your day for that task."},
  {e:'medium',a:'work',t:['MO','MD','AF'],w:'any',mins:30,label:'Important meeting prep',text:"Spend 30 minutes preparing properly for your most important upcoming meeting — review context, write an agenda, prepare any materials, think through what you want to achieve. Good preparation multiplies a meeting's value more than anything else."},
  {e:'medium',a:'work',t:['MO','MD','AF'],w:'any',mins:45,label:'Write or create',text:"Spend 45 minutes in creation mode — writing, designing, coding, building. Start with an outline if needed, then write without stopping to perfect. First drafts, first versions, rough prototypes: everything valuable starts as something imperfect."},
  {e:'medium',a:'work',t:['MO','MD','AF'],w:'any',mins:30,label:'Problem-solving session',text:"Pick one problem at work that's been unresolved and spend 30 minutes working on it with proper focus — write the problem clearly, brainstorm approaches, test the best one. Medium energy is ideal for this kind of analytical thinking."},
  {e:'medium',a:'work',t:['LN','NI'],w:'any',mins:5,label:'End work and sleep',text:"It's late. Working further past this point produces output of diminishing quality while depleting tomorrow's energy. The smartest work decision you can make right now is to shut down properly and sleep. Tomorrow's session will be worth more."},
  {e:'medium',a:'work',t:['AF','EV'],w:'any',mins:30,label:'Team communication catch-up',text:"Spend 30 minutes clearing your professional communications — meaningful responses to Slack, Teams, or email threads. Write with real attention and care. Good written communication is high-leverage and often only happens when someone actually makes time for it."},
  {e:'medium',a:'work',t:['MO','MD','AF'],w:'any',mins:35,label:'Project milestone push',text:"Identify where you are on your current project and push deliberately toward the next milestone for 35 minutes. Milestone-driven work keeps momentum visible and makes progress feel concrete rather than amorphous."},
  {e:'medium',a:'work',t:['MO','MD','AF'],w:'any',mins:40,label:'Learning with application',text:"Spend 40 minutes learning something directly applicable to your work — a new tool feature, a technique, a process. Then immediately apply it to something real. The application gap is where most professional learning disappears."},
  {e:'medium',a:'work',t:['MO','AF'],w:'any',mins:25,label:'High-value email writing',text:"Write the important emails you've been avoiding — the ones that require care, nuance, or difficult content. Medium energy is exactly right for this. Draft, review once, send. Don't let important communication sit because you're waiting to feel ready."},
  {e:'medium',a:'work',t:['MO','MD','AF'],w:'any',mins:45,label:'Code or technical work',text:"Sit down for a 45-minute technical session — coding, analysis, building, debugging. Set the timer, trust the process, and focus on making meaningful progress on one technical goal rather than switching between tasks."},
  {e:'medium',a:'work',t:['MO','MD','AF'],w:'any',mins:30,label:'Strategic thinking time',text:"Block 30 minutes for strategic thinking with no deliverable required — reflect on where your project or work is heading, what's working, what isn't, and what one change would have the most impact. Thinking time is undervalued work."},
  {e:'medium',a:'work',t:['MD'],w:'any',mins:20,label:'Lunch + real break',text:"Take a proper lunch break — step away from your desk, eat real food, and don't look at work for 20 minutes. Coming back after an actual break produces better work than pushing through. This is strategy, not laziness."},
  {e:'medium',a:'work',t:['AF','EV'],w:'any',mins:30,label:'Review and iterate',text:"Spend 30 minutes reviewing work you completed earlier — a document, a design, a piece of code — and improve it with fresh perspective. The difference between good work and great work is almost always in the iteration."},

  // ── WORK · HIGH ──────────────────────────────────────────────────────────
  {e:'high',a:'work',t:['MO','MD','AF'],w:'any',mins:90,label:'Extended deep work block',text:"Block 90 minutes of uninterrupted deep work on your most important project. Phone in another room, notifications blocked, one task only. High energy combined with this much protected time produces the kind of output that moves things meaningfully forward."},
  {e:'high',a:'work',t:['MO'],w:'any',mins:30,label:'Ambitious day plan',text:"Spend 30 minutes building an ambitious but realistic plan for today — not a list, a time-blocked schedule with a primary mission. High-energy days are rare; plan this one with the intentionality it deserves."},
  {e:'high',a:'work',t:['MO','MD','AF'],w:'any',mins:60,label:'Big creative session',text:"Spend 60 minutes on your most ambitious creative work — the presentation that should be great, the piece you want to be proud of, the product that should be excellent. High energy is the fuel for work that exceeds good."},
  {e:'high',a:'work',t:['MO','MD','AF'],w:'any',mins:45,label:'Hard problem, full focus',text:"Take the most difficult, most avoided problem at work and spend 45 uninterrupted minutes on it. High energy means your cognitive ceiling is at its highest right now. Don't spend it on easy tasks."},
  {e:'high',a:'work',t:['MO','MD','AF'],w:'any',mins:60,label:'Ship something',text:"Whatever is closest to done — ship it. Spend 60 minutes completing and releasing a piece of work to the world. Finished and imperfect beats perfect and perpetually almost ready. High energy is the best time to push past the last 20%."},
  {e:'high',a:'work',t:['MO','MD','AF'],w:'any',mins:45,label:'Lead or unblock your team',text:"Spend 45 minutes actively leading — give feedback, unblock colleagues, make the difficult decisions that are waiting on you. High energy means you have the headspace for nuanced, high-stakes communication. Use it in service of others' progress too."},
  {e:'high',a:'work',t:['LN','NI'],w:'any',mins:5,label:'Stop and sleep',text:"High energy late at night is a trap. Tomorrow's performance depends on tonight's sleep more than on another hour of work now. Shut down, protect tomorrow's high-energy window, and sleep. The work will still be there — and you'll do it better rested."},
  {e:'high',a:'work',t:['MO','MD','AF'],w:'any',mins:60,label:'Full project sprint',text:"Run a 60-minute sprint on a project that matters — complete a full feature, finish a full draft, close a backlog of issues. Sprint methodology works because it creates urgency. Set a real goal, start the timer, and don't stop until it rings."},
  {e:'high',a:'work',t:['MO','AF'],w:'any',mins:30,label:'Pitch or present',text:"Record yourself presenting your work, pitch a new idea to a colleague, or write the proposal you've been building toward. High energy gives you the confidence and fluency that high-stakes communication demands. Do the scary thing while you have the fuel."},
  {e:'high',a:'work',t:['MO','MD','AF'],w:'any',mins:45,label:'Systems and infrastructure',text:"Spend 45 minutes on work infrastructure — build the template, write the process document, set up the automation, refactor the codebase. High-energy investment in systems compounds forever. Do the work that prevents future rework."},

  // ══════════════════════════════════════════════════════════════════════════
  // LEARNING
  // ══════════════════════════════════════════════════════════════════════════

  // ── LEARNING · DEPLETED ──────────────────────────────────────────────────
  {e:'depleted',a:'learning',t:['LN','EM','MO','MD','AF','EV','NI'],w:'any',mins:5,label:'Watch one short video',text:"Find one short educational video on something you're curious about — 5 minutes on YouTube, a TED talk excerpt, a quick explainer. Passive learning is completely valid when you're depleted. Let something interesting land in your head."},
  {e:'depleted',a:'learning',t:['LN','EM','MO','MD','AF','EV','NI'],w:'any',mins:5,label:'Read one article',text:"Open one article you've saved and read it slowly. One article. Don't open five tabs, don't queue more. Read one thing to completion and stop. Finishing one thing beats starting ten when you're running on empty."},
  {e:'depleted',a:'learning',t:['LN','EV','NI'],w:'any',mins:10,label:'Audiobook or podcast',text:"Put on an audiobook or podcast on something you want to know more about. Lie down and close your eyes while it plays. Passive audio learning doesn't require you to hold a book or look at a screen — it's learning at zero physical cost."},
  {e:'depleted',a:'learning',t:['MO','MD','AF'],w:'any',mins:5,label:'Review your notes',text:"Open your last set of notes from something you've been studying and re-read them for 5 minutes. Spaced repetition — reviewing what you've already learned — is one of the most powerful learning techniques and costs almost nothing when depleted."},
  {e:'depleted',a:'learning',t:['LN','NI','EV'],w:'any',mins:5,label:'Learn one new thing',text:"Google one thing you've always been mildly curious about and read the top result. One thing. Curiosity doesn't require high energy — it just requires permission to be small. Learning doesn't have to be structured to count."},
  {e:'depleted',a:'learning',t:['MO','MD','AF'],w:'any',mins:5,label:'Vocabulary or flashcards',text:"Open your flashcard app or a language learning app and do 5 minutes of passive review. Spaced repetition at low effort is one of the highest-return learning activities there is. The compounding effect over months is enormous."},
  {e:'depleted',a:'learning',t:['LN','EV','NI'],w:'any',mins:10,label:'Documentary episode',text:"Put on a documentary episode on something you want to understand better. Let it play on your TV or laptop while you rest. Visual learning at low stakes is completely legitimate. You'll absorb more than you expect."},
  {e:'depleted',a:'learning',t:['LN','NI'],w:'any',mins:5,label:'Save content for later',text:"Spend 5 minutes curating — save articles, videos, and talks you want to engage with when energy is higher. Building a good reading list is itself a form of intentional learning practice. Future you will have good material to work with."},
  {e:'depleted',a:'learning',t:['MO','MD','AF'],w:'any',mins:5,label:'Mind map from memory',text:"Draw a quick mind map from memory of the last thing you studied — main concept in the centre, branches out from memory. Retrieval practice, even at this tiny scale, dramatically strengthens long-term retention compared to re-reading."},
  {e:'depleted',a:'learning',t:['MO','MD','AF'],w:'any',mins:5,label:'One practice problem',text:"Do one practice problem, one example exercise, or one small quiz question in whatever you're learning. One. Completing one builds the habit more reliably than planning to do twenty when you have more energy."},

  // ── LEARNING · LOW ───────────────────────────────────────────────────────
  {e:'low',a:'learning',t:['MO','MD','AF','EV'],w:'any',mins:20,label:'Focused reading session',text:"Pick the book or article you're working through and read for 20 focused minutes — no phone beside you, no interruptions. Stop at 20 minutes. Low energy is sufficient for reading at a pace that actually absorbs rather than just scanning."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'any',mins:15,label:'Flashcard review session',text:"Spend 15 minutes in a focused spaced repetition session — Anki, Quizlet, or your own flashcard deck. Low energy is actually ideal for this: the retrieval effort is low but the memory-strengthening effect is compoundingly powerful."},
  {e:'low',a:'learning',t:['MO','MD','AF','EV'],w:'any',mins:20,label:'Tutorial or course lesson',text:"Open the online course or tutorial you've been progressing through and complete one lesson. Low energy is fine for structured video learning — you follow rather than lead. Consistency in the course matters far more than speed."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'any',mins:15,label:'Practice problems',text:"Spend 15 minutes working through practice problems in whatever you're learning — coding exercises, maths problems, language exercises. Active practice beats passive review every time, even in a short session."},
  {e:'low',a:'learning',t:['EV','NI'],w:'any',mins:20,label:'Read before bed',text:"Read a non-fiction book or long-form article for 20 minutes before you sleep. Evening reading consolidates information learned during the day. What you read in the hour before sleep is disproportionately well retained."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'any',mins:20,label:'Write summary notes',text:"Spend 20 minutes writing a summary of what you've learned recently — in your own words, from memory where possible. Writing summaries is one of the most underused and most powerful learning techniques available."},
  {e:'low',a:'learning',t:['MO','MD','AF','EV'],w:'in',mins:20,label:'Podcast deep-dive',text:"Find a high-quality podcast episode on a topic you want to understand better and listen with a notepad beside you. Jot down 3-5 things that stand out. Active listening — even just writing a few words — triples retention compared to passive listening."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'any',mins:15,label:'Concept review session',text:"Choose one concept you've recently covered that feels fuzzy and spend 15 minutes on it specifically — re-read the relevant section, watch one short video, write a definition in your own words. Targeted review beats broad re-reading."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'any',mins:20,label:'Implement one small thing',text:"Take one thing you've learned recently and implement it in a small, real context — run the code, apply the technique, try the method. Implementation closes the loop that reading opens. Even a tiny application builds genuine competence."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'any',mins:20,label:'Teach it briefly',text:"Write a short explanation of something you've been learning as if you're explaining it to a friend who doesn't know it. The Feynman method — teaching forces you to identify and close the gaps in your own understanding."},
  {e:'low',a:'learning',t:['MO','AF'],w:'out',mins:15,label:'Walk and listen',text:"Take a 15-minute walk and listen to an educational podcast or audiobook. Combining light movement with audio learning is a surprisingly efficient use of both low energy and low-intensity exercise time."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'any',mins:15,label:'Curate your learning queue',text:"Spend 15 minutes reviewing what you're working on learning and deciding what to focus on next — which course, which book, which skill. Intentional direction prevents random dabbling and makes each learning session count more."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'any',mins:20,label:'Dictionary and depth',text:"Pick 5-10 terms from your field that you use but couldn't define precisely and look them up properly. Write each definition in your own words. Vocabulary precision is the foundation that everything else in a discipline is built on."},
  {e:'low',a:'learning',t:['EV','NI'],w:'any',mins:15,label:'Evening review',text:"Spend 15 minutes reviewing what you covered today — flip through your notes, recall the key points, jot down questions. Evening review on the day of learning produces dramatically better retention than waiting for the weekend."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'any',mins:20,label:'Secondary source reading',text:"Find and read a supplementary article, blog post, or paper on something you're studying. Encountering the same idea through a different voice, framing, or example dramatically deepens understanding beyond what any single source provides."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'any',mins:15,label:'Annotate your reading',text:"Go back to something you've read and annotate it — underline key ideas, write brief reactions in the margins, mark questions you still have. Active annotation while reading roughly triples retention compared to passive reading."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'any',mins:20,label:'Build on existing notes',text:"Open a note you made earlier in your current learning journey and expand it — add more context, link it to other ideas, fill in gaps. Notes that compound over time become far more valuable than notes written and never revisited."},

  // ── LEARNING · MEDIUM ────────────────────────────────────────────────────
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:45,label:'Deep study session',text:"Sit down for a proper 45-minute study session on your primary learning goal. Use the Pomodoro method if it helps — 25 minutes focused, 5-minute break, repeat. Medium energy is ideal for deep learning that requires real cognitive engagement."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:30,label:'Build a project',text:"Spend 30 minutes building something small with what you've learned — a mini project, a code snippet, a short essay. Applied learning is permanently retained; passive learning fades within a week. Make something today."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:40,label:'Work through a hard problem',text:"Find the hardest practice problem or exercise you have and spend 40 minutes on it without looking at the solution. Struggle is where learning actually happens — the discomfort of not knowing is the experience of getting better."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:35,label:'Concept mastery session',text:"Choose one concept you've been treating as understood but couldn't fully explain and spend 35 minutes achieving real mastery — multiple sources, practice, your own written explanation. Real understanding, not familiarity."},
  {e:'medium',a:'learning',t:['LN','NI'],w:'any',mins:5,label:'Wrap up and sleep',text:"It's late and your brain is consolidating what you've learned today during sleep. Staying up further to study more is counterproductive — sleep deprivation reduces memory consolidation significantly. Your best next move is to sleep now."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:30,label:'Write to learn',text:"Write a 500-word explanation of the core idea you're studying — not for anyone else, for yourself. Writing forces retrieval, exposes fuzzy thinking, and produces something you can return to. The act of writing is itself learning."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:45,label:'Structured practice drill',text:"Design and run 45 minutes of structured practice drills — real problems, real attempts, checking answers carefully. Deliberate practice with feedback is the only thing that reliably produces mastery. Repetition without feedback produces habit, not skill."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:35,label:'Read and implement',text:"Read a chapter or section of whatever you're studying, then immediately implement or apply what you've just read. The read-implement loop is far more powerful than reading large volumes passively and planning to apply it 'later'."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:40,label:'Peer learning session',text:"Explain what you've been learning to someone else — a friend, a colleague, or even a voice recording. Teaching while the material is fresh produces deeper encoding than any amount of re-reading."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:30,label:'Test yourself rigorously',text:"Cover your notes and test yourself on 20-30 questions, problems, or concepts from what you've been studying. Write your answers before checking. Retrieval practice — the testing effect — produces roughly twice the retention of re-reading."},
  {e:'medium',a:'learning',t:['MO','AF'],w:'in',mins:45,label:'Focused online course block',text:"Complete two or three lessons in your current online course back to back, pausing to take notes as you go. Medium energy is ideal for structured video learning — follow along, build notes, and finish the block properly."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:30,label:'Research and synthesise',text:"Research a topic adjacent to your main learning goal and synthesise what you find into a short note or outline. Connecting new areas to your existing knowledge builds the kind of deep understanding that narrow study alone doesn't produce."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:40,label:'Complete a mini project',text:"Set a 40-minute timer and build a small, complete project using what you know — finish it before the timer ends, even if imperfect. Small finished projects compound into a portfolio of real evidence that you know what you're learning."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:25,label:'Vocabulary and terminology',text:"Spend 25 minutes going deep on the precise terminology of your field — pick 10 terms, write precise definitions, find examples of each in context. Technical vocabulary precision is what distinguishes intermediate from advanced practitioners."},

  // ── LEARNING · HIGH ──────────────────────────────────────────────────────
  {e:'high',a:'learning',t:['MO','MD','AF'],w:'any',mins:90,label:'Extended learning sprint',text:"Block 90 minutes for a genuine learning sprint — go deep into the most complex, most challenging material you have. High energy gives you the cognitive resources for the kind of difficult thinking that produces real breakthroughs in understanding."},
  {e:'high',a:'learning',t:['MO','MD','AF'],w:'any',mins:60,label:'Build something real',text:"Spend 60 minutes building a real, complete project with what you've learned — something you can show, share, or use. High energy is for making things that last. Build something today that demonstrates real capability."},
  {e:'high',a:'learning',t:['MO','MD','AF'],w:'any',mins:45,label:'Attack the hardest material',text:"Find the material that has been most difficult and has felt most out of reach and spend 45 minutes attacking it directly. High energy means your cognitive ceiling is at its highest. Don't save hard material for better conditions — you're in them now."},
  {e:'high',a:'learning',t:['MO','MD','AF'],w:'any',mins:60,label:'Write to publish',text:"Write a long-form piece on what you've been learning with the intention of publishing or sharing it — a blog post, a detailed note, a thread. Writing for an audience raises your standards and clarifies your thinking dramatically."},
  {e:'high',a:'learning',t:['MO','MD','AF'],w:'any',mins:45,label:'Teach someone directly',text:"Find someone to teach — arrange a call, a meeting, or a session where you explain what you've been learning. High energy makes teaching feel energising rather than draining. Teaching is the most powerful consolidation method there is."},
  {e:'high',a:'learning',t:['LN','NI'],w:'any',mins:5,label:'Stop and let it consolidate',text:"High energy at this hour will cost tomorrow's performance. Sleep is when your brain physically consolidates what you've learned today — without it, the learning doesn't fully form. Put the books down and let tonight's sleep do its work."},
  {e:'high',a:'learning',t:['MO','MD','AF'],w:'any',mins:60,label:'Research deep dive',text:"Choose one area within your field and do a genuine deep dive for 60 minutes — primary sources, academic papers, the best books. High energy means you can engage with complex material at depth. Don't squander it on easy reading."},
  {e:'high',a:'learning',t:['MO','MD','AF'],w:'any',mins:45,label:'Deliberate practice block',text:"Design and run 45 minutes of maximally challenging deliberate practice — problems just beyond your current ability level, with careful attention to your errors and what they reveal. This is the zone where skill is actually built."},
  {e:'high',a:'learning',t:['MO','MD','AF'],w:'any',mins:30,label:'Review and share learnings',text:"Write a structured review of what you've learned this week and share it — post it, send it to a friend, or submit it somewhere. The discipline of articulating and sharing your learning makes you meaningfully more rigorous about it."},

  // ══════════════════════════════════════════════════════════════════════════
  // RELATIONSHIPS
  // ══════════════════════════════════════════════════════════════════════════

  // ── RELATIONSHIPS · DEPLETED ─────────────────────────────────────────────
  {e:'depleted',a:'relationships',t:['LN','EM','MO','MD','AF','EV','NI'],w:'any',mins:3,label:'Send one kind message',text:"Open your messages and send one short, genuine message to someone you care about — 'thinking of you', 'hope you're well', anything real. Three minutes. Relationships don't always require grand gestures; they require consistent small ones."},
  {e:'depleted',a:'relationships',t:['LN','EM','MO','MD','AF','EV','NI'],w:'any',mins:3,label:'Like or comment thoughtfully',text:"Find one recent post from a friend or family member and leave a genuine, specific comment — not just 'nice' but something that shows you actually looked. Small acknowledgement costs almost nothing and means more than most people admit."},
  {e:'depleted',a:'relationships',t:['EV','NI'],w:'any',mins:5,label:'Plan a future catch-up',text:"Think of one person you've been meaning to reconnect with and send a message suggesting a specific time to catch up. You don't need energy to initiate — just the intention. When depleted, planning something for later is a genuine act of care."},
  {e:'depleted',a:'relationships',t:['LN','NI','EV'],w:'any',mins:5,label:'Reply to a message',text:"Go through your messages and reply to one conversation you've been leaving on read. Even a brief, honest reply — 'been quiet lately, hope you're good' — maintains connection better than silence while you wait to feel ready for a longer response."},
  {e:'depleted',a:'relationships',t:['MO','MD','AF'],w:'any',mins:5,label:'Share something interesting',text:"Find one thing — an article, a meme, a video — that would genuinely interest someone you care about and send it to them with a short note about why you thought of them. It takes 5 minutes and says: I thought of you today."},
  {e:'depleted',a:'relationships',t:['LN','EM'],w:'any',mins:3,label:'Write an unsent message',text:"Write out what you actually want to say to someone important in your life — not to send, just to get it out of your head. The act of articulating feelings, even privately, reduces the weight of carrying them and is a form of emotional clarity."},
  {e:'depleted',a:'relationships',t:['MO','MD','AF'],w:'any',mins:5,label:'Check in on one person',text:"Think of one person who might be going through something hard and send them a brief check-in message. A simple 'hey, how are you actually doing?' from someone who means it lands differently than almost any other kind of communication."},
  {e:'depleted',a:'relationships',t:['EV','NI'],w:'any',mins:5,label:'Gratitude to someone specific',text:"Write a 3-5 sentence note of genuine gratitude to one specific person and send it to them. Expressing specific appreciation — 'the way you did X meant Y to me' — is one of the highest-impact relationship acts you can do in 5 minutes."},

  // ── RELATIONSHIPS · LOW ──────────────────────────────────────────────────
  {e:'low',a:'relationships',t:['MO','MD','AF','EV'],w:'any',mins:15,label:'Phone call with someone close',text:"Call one person you care about and have a real conversation for 15 minutes. Ask about something specific in their life. Listen more than you talk. Voice calls maintain connection in ways that text exchanges genuinely cannot replicate."},
  {e:'low',a:'relationships',t:['MO','MD','AF'],w:'any',mins:20,label:'Write a meaningful letter',text:"Write a longer message or email to someone important — update them on your life, ask about theirs, say something you've been meaning to say. Asynchronous written connection is legitimate and valued, especially between busy people."},
  {e:'low',a:'relationships',t:['MO','MD','AF','EV'],w:'any',mins:15,label:'Plan a specific catch-up',text:"Choose one person you want to see more of and send a message with two or three specific times you're available this month. Waiting for 'sometime soon' is the reason most reconnections never happen. Concrete plans do."},
  {e:'low',a:'relationships',t:['EV'],w:'any',mins:20,label:'Cook together or call while cooking',text:"Call a friend or family member and have them on speaker while you both cook your separate dinners. Parallel activity calls remove the pressure of 'catching up' and often produce the most natural conversations."},
  {e:'low',a:'relationships',t:['MO','MD','AF'],w:'any',mins:20,label:'Write and send appreciation',text:"Write a thoughtful note of appreciation to two or three people in your life — specific, genuine, a little longer than a text. Scheduled appreciation is one of the highest-leverage relationship investments available."},
  {e:'low',a:'relationships',t:['MO','MD','AF','EV'],w:'any',mins:15,label:'Video call a faraway person',text:"Video call someone who lives far away — a friend in a different city, family abroad. Low energy is fine for connection calls; you don't need to perform. Just show up and let the distance shrink for 15 minutes."},
  {e:'low',a:'relationships',t:['MO','MD','AF'],w:'any',mins:20,label:'Remember and acknowledge',text:"Look through your calendar or notes for upcoming events in the lives of people close to you — birthdays, interviews, difficult days — and send them a message now, before you forget. Being remembered at the right moment is a meaningful gift."},
  {e:'low',a:'relationships',t:['AF','EV'],w:'out',mins:20,label:'Walk with someone',text:"Ask someone to join you for a 20-minute walk — a colleague, a housemate, a partner. Side-by-side conversations are often easier and more honest than face-to-face ones. The movement is a bonus; the connection is the point."},
  {e:'low',a:'relationships',t:['MO','MD','AF'],w:'any',mins:15,label:'Update your closest people',text:"Send a brief personal update to the few people who genuinely want to know how you're doing. Connection requires reciprocal visibility. Share something real about what's going on for you — not just logistics, but something honest."},
  {e:'low',a:'relationships',t:['EV','NI'],w:'any',mins:20,label:'Watch something together',text:"Start a watch party or synchronised watch session with a friend — pick a show episode or short documentary and watch at the same time while messaging about it. A low-stakes, low-energy way to spend time together across distance."},
  {e:'low',a:'relationships',t:['MO','MD','AF'],w:'any',mins:15,label:'Reconnect with one old friend',text:"Think of one friend you haven't spoken to in a long time and send them a message with a real update and a specific question about their life. Most reconnections fail because no one goes first. Go first."},
  {e:'low',a:'relationships',t:['MO','MD','AF'],w:'any',mins:20,label:'Relationship maintenance',text:"Go through your phone contacts and message 3-5 people you value but haven't spoken to in a while. Brief is fine — something real, something that acknowledges the specific person. Maintenance like this keeps relationships alive through life's busy periods."},

  // ── RELATIONSHIPS · MEDIUM ───────────────────────────────────────────────
  {e:'medium',a:'relationships',t:['MO','MD','AF','EV'],w:'any',mins:30,label:'Meaningful coffee or call',text:"Arrange or have a 30-minute proper conversation with someone important — ask about the things that matter in their life right now, share what's going on in yours. Medium energy is ideal for the real conversations that build close relationships."},
  {e:'medium',a:'relationships',t:['EV'],w:'out',mins:45,label:'Social plan tonight',text:"Make plans to see someone tonight — dinner, drinks, a walk, anything. A lot of social isolation happens not from lack of want but from lack of concrete plans. Send the message now, while you have the energy to follow through on it."},
  {e:'medium',a:'relationships',t:['MO','MD','AF'],w:'any',mins:30,label:'Write something heartfelt',text:"Write a proper letter or long message to someone who matters to you — with care and genuine reflection. Tell them what they mean to you, what you've appreciated, what you hope for them. This kind of communication is rare and remembered."},
  {e:'medium',a:'relationships',t:['EV','AF'],w:'out',mins:45,label:'Cook for someone',text:"Cook a meal for someone who would appreciate it — a partner, a friend, a family member. The act of cooking for someone is one of the most direct expressions of care available, and it creates a shared experience that lasts in memory."},
  {e:'medium',a:'relationships',t:['MO','MD','AF'],w:'any',mins:25,label:'Conflict resolution',text:"If there's something unresolved with someone important, spend 25 minutes composing a thoughtful message or preparing what you want to say. Unresolved conflicts quietly drain relationship quality over time. Medium energy gives you the steadiness to approach it well."},
  {e:'medium',a:'relationships',t:['MO','MD','AF'],w:'any',mins:30,label:'Plan a shared experience',text:"Organise something specific to do with someone you want to be closer to — book tickets, plan a trip, schedule a recurring thing. Shared experiences build relationships faster than conversations about them. Make the plan today."},
  {e:'medium',a:'relationships',t:['EV','AF'],w:'out',mins:45,label:'Active socialising',text:"Do something social and slightly active — a group walk, a sport, frisbee in the park, a bike ride together. Relationships formed and deepened through shared physical activity have a different quality than those built only through conversation."},
  {e:'medium',a:'relationships',t:['LN','NI'],w:'any',mins:5,label:'End the evening, connect tomorrow',text:"It's late. Send a brief goodnight message to someone you care about, then sleep. Well-rested you will be a better friend, partner, and family member than tired-you straining to be present. Connect properly tomorrow."},
  {e:'medium',a:'relationships',t:['MO','MD','AF'],w:'any',mins:35,label:'Check in on several people',text:"Spend 35 minutes having brief, genuine check-ins with 5-6 people in your life — voice notes, messages, short calls. Breadth of connection maintained across your network prevents the gradual drift that happens when life gets busy."},
  {e:'medium',a:'relationships',t:['EV','AF'],w:'any',mins:30,label:'Game or activity together',text:"Play a game, work on a puzzle, or do a shared activity with someone you live with or can meet. Side-by-side activities that aren't just screens create the kind of easy shared presence that close relationships are built from."},

  // ── RELATIONSHIPS · HIGH ─────────────────────────────────────────────────
  {e:'high',a:'relationships',t:['AF','EV'],w:'out',mins:90,label:'Full social evening',text:"Make tonight a proper social evening — invite people over, go out together, plan something with real effort. High energy means you can be fully present rather than half-there. Bring the version of yourself that other people love spending time with."},
  {e:'high',a:'relationships',t:['MO','MD','AF'],w:'any',mins:45,label:'Deep conversation',text:"Have a genuinely deep conversation with someone close — the kind where you both learn something about each other. High energy means you can ask harder questions and really listen to the answers rather than just performing attention."},
  {e:'high',a:'relationships',t:['AF','EV'],w:'out',mins:60,label:'Plan and host something',text:"Organise something — a dinner, a gathering, a day trip — and actually make it happen. High energy is for the kind of social initiative that requires logistics, warmth, and sustained attention to what others need. Be the person who brings people together."},
  {e:'high',a:'relationships',t:['LN','NI'],w:'any',mins:5,label:'Good night — sleep well',text:"Even at high energy, being a good presence for the people in your life tomorrow requires being rested today. Say goodnight properly and sleep. The relationship investment is in showing up as your full self — and that starts with rest."},
  {e:'high',a:'relationships',t:['MO','MD','AF'],w:'any',mins:60,label:'Repair or deepen a key relationship',text:"Identify the most important relationship in your life that needs attention and spend 60 minutes giving it real focus — a long call, a planned conversation, a letter, a visit. High energy gives you the emotional bandwidth for relationship work that matters."},
  {e:'high',a:'relationships',t:['AF','EV'],w:'out',mins:90,label:'Group activity or adventure',text:"Organise or join a group activity that requires real coordination — a hike, a sport, a day trip, a project together. Group experiences at high energy produce the kind of shared memories and deepened bonds that are the backbone of long friendships."},
  {e:'high',a:'relationships',t:['MO','AF'],w:'any',mins:30,label:'Reach out widely',text:"Spend 30 minutes reaching out to 8-10 people across your network — warm, personal, specific messages to people at different levels of closeness. High social energy is rare; use it to invest in connection you want to maintain."},

  // ══════════════════════════════════════════════════════════════════════════
  // MINDFULNESS
  // ══════════════════════════════════════════════════════════════════════════

  // ── MINDFULNESS · DEPLETED ───────────────────────────────────────────────
  {e:'depleted',a:'mindfulness',t:['LN','EM','MO','MD','AF','EV','NI'],w:'any',mins:3,label:'3 deep breaths',text:"Just take 3 slow, deliberate breaths — in through your nose for 5 counts, out through your mouth for 7. That's everything. Three breaths, done with full attention, genuinely shift your nervous system state. Small thing, real effect."},
  {e:'depleted',a:'mindfulness',t:['LN','EM','MO','MD','AF','EV','NI'],w:'any',mins:5,label:'Body scan',text:"Sit or lie down and slowly move your attention through your body from feet to head. Don't try to change anything — just notice. Tension, warmth, tightness, ease. This 5-minute practice is one of the most restorative things you can do."},
  {e:'depleted',a:'mindfulness',t:['LN','NI','EV'],w:'any',mins:5,label:'Gratitude for 3 things',text:"Before you sleep or rest, write down or mentally note 3 things — however small — that you're grateful for today. Depleted days make this harder and more important simultaneously. Even finding three things shifts your mental state measurably."},
  {e:'depleted',a:'mindfulness',t:['MO','EM'],w:'out',mins:5,label:'Mindful 5 minutes outside',text:"Step outside for 5 minutes and use all your senses — what can you see, hear, smell, feel on your skin? Put your phone away. This simple sensory grounding breaks cycles of anxious thought and reconnects you to the present moment."},
  {e:'depleted',a:'mindfulness',t:['LN','NI','EV'],w:'any',mins:5,label:'4-7-8 breathing',text:"Try 4-7-8 breathing: inhale for 4 counts, hold for 7, exhale for 8. Repeat 4 times. This pattern activates the parasympathetic nervous system more reliably than almost any other brief intervention. It feels strange at first. It works."},
  {e:'depleted',a:'mindfulness',t:['LN','EM','MO','MD','AF','EV','NI'],w:'any',mins:5,label:'Sit with no agenda',text:"Set a timer for 5 minutes and simply sit. No phone, no task, no goal. When thoughts arrive, notice them and let them pass. You're not trying to empty your mind — you're practicing noticing without being pulled away. That's mindfulness."},
  {e:'depleted',a:'mindfulness',t:['LN','NI'],w:'any',mins:5,label:'Loving-kindness for yourself',text:"Lie down and silently repeat: 'May I be well. May I be at peace. May I be kind to myself.' Do this for 5 minutes. When depleted, the critical voice gets loud. Actively countering it with intentional self-compassion is not weakness — it's maintenance."},
  {e:'depleted',a:'mindfulness',t:['MO','EM'],w:'any',mins:3,label:'Set one intention',text:"Before the day begins or before you get up, set one simple intention for the next few hours — not a task, but a way of being. 'I'll move slowly today', 'I'll be kind to myself', 'I'll do one thing at a time'. Intention shapes experience."},
  {e:'depleted',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:5,label:'Mindful cup of tea or coffee',text:"Make your next hot drink with full attention — watch the water, smell the tea, hold the warmth of the cup. Drink it without a screen, without planning, without doing anything else. Five minutes of full presence, right where you already are."},
  {e:'depleted',a:'mindfulness',t:['LN','NI','EV'],w:'any',mins:5,label:'Write 3 sentences about today',text:"Write 3 honest sentences about how today actually felt. Don't judge the sentences — just write what's true. Brief journalling at depleted moments often surfaces things you needed to name and didn't realise were sitting there."},

  // ── MINDFULNESS · LOW ────────────────────────────────────────────────────
  {e:'low',a:'mindfulness',t:['MO','MD','AF','EV'],w:'any',mins:10,label:'Guided meditation',text:"Open a meditation app or search 'guided meditation 10 minutes' on YouTube and follow along. Guided is better than unguided at low energy because the voice carries you. Ten minutes of followed guidance is enough to shift the rest of the hour."},
  {e:'low',a:'mindfulness',t:['MO','MD','AF','EV'],w:'any',mins:15,label:'Journalling session',text:"Write freely for 15 minutes — no topic, no structure, just whatever is present. Morning pages or stream-of-consciousness writing reliably clears mental fog, reduces anxiety, and often surfaces clarity that wasn't accessible before writing."},
  {e:'low',a:'mindfulness',t:['MO','AF'],w:'out',mins:15,label:'Mindful walk',text:"Take a 15-minute walk with your phone in your pocket and your attention on your surroundings. Notice your footsteps, the air, the sounds, the light. A mindful walk is a meditation that doesn't require sitting still — often more accessible at low energy."},
  {e:'low',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:10,label:'Breathing practice',text:"Spend 10 minutes on a structured breathing practice — box breathing, coherent breathing, or the 4-7-8 technique. Pick one and do it properly. Intentional breathwork reliably reduces cortisol, improves heart rate variability, and steadies scattered thinking."},
  {e:'low',a:'mindfulness',t:['EV','NI'],w:'any',mins:15,label:'Evening reflection',text:"Spend 15 minutes writing a genuine reflection on today — what went well, what was hard, what you noticed about yourself. Evening reflection consistently improves clarity, reduces overnight rumination, and makes the next day more intentional."},
  {e:'low',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:10,label:'Gratitude journalling',text:"Write 5-7 things you're genuinely grateful for with specific detail — not 'my health' but 'that I could walk to the kitchen this morning without thinking about it'. Specificity activates the gratitude more fully than vague general statements."},
  {e:'low',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:15,label:'Values reflection',text:"Spend 15 minutes thinking and writing about your core values — what they are, whether you're currently living in alignment with them, and one small way you could honour them more this week. Values clarity is a form of deep mindfulness."},
  {e:'low',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:10,label:'RAIN technique',text:"Work through the RAIN technique — Recognise what you're feeling, Allow it to be there, Investigate it with curiosity, and Nurture yourself through it. This 10-minute self-inquiry practice is specifically designed for difficult emotions at low energy."},
  {e:'low',a:'mindfulness',t:['MO','AF'],w:'out',mins:20,label:'Sit in nature quietly',text:"Find a park, garden, or any outdoor space and sit quietly for 20 minutes without your phone. Watch what's moving, listen to what's there, feel the air. Passive nature exposure consistently reduces markers of stress without requiring any effort."},
  {e:'low',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:15,label:'Digital detox window',text:"Spend 15 minutes completely offline — no phone, no laptop, no media of any kind. This is harder than it sounds and more effective than almost anything else for restoring the felt sense of mental spaciousness that modern life systematically removes."},
  {e:'low',a:'mindfulness',t:['EV','NI'],w:'any',mins:10,label:'Self-compassion practice',text:"Spend 10 minutes deliberately practising self-compassion — acknowledge what's been hard, remind yourself that difficulty is universal, and offer yourself the warmth you'd give a good friend in the same situation. Self-compassion is a practised skill, not a personality trait."},
  {e:'low',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:10,label:'5-4-3-2-1 grounding',text:"Use the 5-4-3-2-1 grounding technique — name 5 things you can see, 4 you can touch, 3 you can hear, 2 you can smell, 1 you can taste. Full sensory grounding rapidly interrupts rumination and anxiety spirals and costs nothing at all."},
  {e:'low',a:'mindfulness',t:['LN','NI','EV'],w:'any',mins:10,label:'Wind-down mindfulness',text:"Do a 10-minute gentle wind-down mindfulness practice before sleep — focus on breathing, body sensation, and letting thoughts pass without following them. A consistent bedtime mindfulness practice improves both sleep quality and morning clarity."},
  {e:'low',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:15,label:'Intention setting ritual',text:"Spend 15 minutes setting a clear, specific intention for the rest of today — not a goal, but a commitment to how you want to show up. Write it down. Intentions revisited throughout the day act as continuous gentle course corrections."},
  {e:'low',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:10,label:'Single-task practice',text:"Choose one simple task — making tea, washing dishes, folding laundry — and do it with complete undivided attention. Notice every sensation, every movement. Single-tasking as mindfulness practice is available inside the activities you were already doing."},

  // ── MINDFULNESS · MEDIUM ─────────────────────────────────────────────────
  {e:'medium',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:25,label:'Meditation session',text:"Sit for a 25-minute meditation — guided or silent, whichever works better for you today. This is enough time to move through the initial restlessness and into real stillness. Medium energy is the ideal state for meditation that goes beyond surface calm."},
  {e:'medium',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:30,label:'Deep journalling',text:"Write for 30 minutes on something you've been avoiding thinking about — a question about your direction, a difficult emotion, a relationship pattern. Medium energy gives you enough groundedness to engage with difficult material without being destabilised by it."},
  {e:'medium',a:'mindfulness',t:['MO','MD','AF','EV'],w:'any',mins:20,label:'Yoga and mindfulness',text:"Do 20 minutes of slow, mindful yoga — move with your breath, hold poses long enough to feel the sensation fully, and practise bringing your attention back every time it wanders. This is physical mindfulness training disguised as stretching."},
  {e:'medium',a:'mindfulness',t:['LN','NI'],w:'any',mins:5,label:'Sleep is the practice tonight',text:"At this hour, the most mindful thing you can do is sleep. Mindfulness is partly about being honest about what your body and mind need. What they need right now is rest, not more reflection. Put down whatever you're holding and sleep."},
  {e:'medium',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:30,label:'Weekly reflection',text:"Spend 30 minutes doing a proper weekly reflection — what went well, what was difficult, what you want to carry forward, and what you want to leave behind. This practice, done consistently, produces a kind of self-knowledge that nothing else quite replicates."},
  {e:'medium',a:'mindfulness',t:['MO','AF'],w:'out',mins:30,label:'Mindful walk in nature',text:"Take a 30-minute walk in nature with full presence — phone away, attention on your surroundings. Walk slowly. Stop occasionally to actually look at something. This isn't exercise; it's a moving meditation that uses the natural environment as the object of attention."},
  {e:'medium',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:25,label:'Body awareness scan',text:"Lie down and spend 25 minutes doing a thorough body awareness scan — moving slowly through each body part, noticing both physical sensation and any associated emotional or mental content. This practice builds the kind of self-awareness that meditation theory says is fundamental."},
  {e:'medium',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:30,label:'Emotional processing',text:"Spend 30 minutes with a difficult emotion that's been present — write about it, sit with it in meditation, or move through it physically. Medium energy gives you the resources to process rather than suppress. Emotions don't go away when ignored; they compound."},
  {e:'medium',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:20,label:'Visualisation practice',text:"Spend 20 minutes on a guided or self-directed visualisation — a goal you're working towards, a value you want to embody, a scenario you want to handle well. Vivid mental rehearsal activates the same neural pathways as physical practice."},
  {e:'medium',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:30,label:'Complete digital detox',text:"Spend 30 minutes with no devices at all. Read a physical book, sit outside, make something with your hands, or simply be. The felt experience of unstructured time without a screen is one of the most profoundly mindful things available in modern life."},
  {e:'medium',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:25,label:'Loving-kindness meditation',text:"Spend 25 minutes on a loving-kindness practice — extend warmth and goodwill progressively to yourself, someone close, someone neutral, someone difficult, and all beings. This specific practice has the strongest evidence base of any meditation form for increasing compassion."},
  {e:'medium',a:'mindfulness',t:['EV'],w:'any',mins:20,label:'Emotion labelling practice',text:"Spend 20 minutes in a mindful review of your emotional state over the last 24 hours — name each emotion precisely, locate it in your body, and note what triggered it without judging. Emotional granularity — the ability to distinguish nuanced states — is a measurable wellbeing predictor."},

  // ── MINDFULNESS · HIGH ───────────────────────────────────────────────────
  {e:'high',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:45,label:'Extended meditation',text:"Sit for a 45-minute meditation session — the first 15 minutes of settling will give way to real depth. High energy is actually a challenge for meditation; use this session to practise with a mind that would rather move. That's where the real skill is built."},
  {e:'high',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:60,label:'Journalling and life review',text:"Spend 60 minutes on a deep life review — where you are, where you're headed, what truly matters, what you're tolerating that you shouldn't be, what you're not doing that you should. High energy is when these questions are most productively engaged."},
  {e:'high',a:'mindfulness',t:['MO','AF'],w:'out',mins:60,label:'Mindful nature immersion',text:"Spend 60 minutes in nature with a real intention to be fully present — no podcasts, no photography, no planning. Just walking, sitting, and noticing. High energy allows you to sustain the quality of attention that this level of immersion requires."},
  {e:'high',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:45,label:'Write a personal manifesto',text:"Spend 45 minutes articulating who you want to be — your values, your commitments, your vision for your life. High energy makes this kind of aspirational clarity-work energising rather than anxiety-provoking. Write something you'll come back to."},
  {e:'high',a:'mindfulness',t:['LN','NI'],w:'any',mins:5,label:'High energy at night: sleep',text:"High energy late at night is the enemy of tomorrow's high energy. The most mindful thing you can do right now is recognise the pattern and break it. Put your phone down, dim everything, and let tonight's rest produce tomorrow's clarity."},
  {e:'high',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:60,label:'Intensive self-inquiry',text:"Spend 60 minutes on deep self-inquiry — pick a question about your life, values, patterns, or direction and stay with it through writing, meditation, and reflection without rushing to an answer. The willingness to sit with real questions is itself a practice."},
  {e:'high',a:'mindfulness',t:['MO','AF'],w:'any',mins:30,label:'Meditation and movement',text:"Combine 20 minutes of sitting meditation with 10 minutes of mindful movement — slow yoga, walking meditation, or tai chi. High energy allows you to bring quality attention to both the stillness and the motion. Different, complementary practices."},
  {e:'high',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:45,label:'Share mindfulness with someone',text:"Teach a short mindfulness practice to someone who might benefit from it — a friend, a colleague, a family member. Sharing what you've learned in this area is both a service and a deepening of your own practice."},

  // ══════════════════════════════════════════════════════════════════════════
  // CREATIVITY
  // ══════════════════════════════════════════════════════════════════════════

  // ── CREATIVITY · DEPLETED ────────────────────────────────────────────────
  {e:'depleted',a:'creativity',t:['LN','EM','MO','MD','AF','EV','NI'],w:'any',mins:5,label:'Doodle freely',text:"Get a pen and paper and doodle for 5 minutes — anything, with no expectation of outcome. Circles, patterns, shapes, faces, nothing recognisable. Depleted creativity isn't dead creativity. It's just tired. Doodling asks almost nothing of it."},
  {e:'depleted',a:'creativity',t:['LN','EV','NI'],w:'any',mins:10,label:'Listen to music with attention',text:"Put on music you love and actually listen to it for 10 minutes — lie down, close your eyes, and follow the sound rather than using it as background. Attentive listening is a form of creative practice and asks nothing more of you than presence."},
  {e:'depleted',a:'creativity',t:['MO','MD','AF'],w:'any',mins:5,label:'Write one sentence',text:"Open a notebook or note and write one single sentence about anything — what you see, what you feel, something weird you noticed. One sentence. Creativity at its most depleted can still produce one honest sentence. That sentence might be the seed of something."},
  {e:'depleted',a:'creativity',t:['LN','EV','NI'],w:'any',mins:10,label:'Read one poem',text:"Find and read one poem — slowly, twice. Let the language land. Poetry is designed to be received rather than processed, and reading it attentively is a restorative creative act available even when you have no creative energy of your own to spend."},
  {e:'depleted',a:'creativity',t:['MO','MD','AF'],w:'any',mins:5,label:'Take one photograph',text:"Look around wherever you are and find one thing worth photographing — a light, a texture, a composition you hadn't noticed before. Take the photo, then put your phone away. Noticing beauty is the seed of all creative work."},
  {e:'depleted',a:'creativity',t:['LN','EV','NI'],w:'any',mins:5,label:'Look at art',text:"Open an art platform — Pinterest, a museum website, an artist's Instagram — and spend 5 minutes looking at work that interests you. No analysis, no studying. Let images move through you. Input precedes output; you're filling the well."},
  {e:'depleted',a:'creativity',t:['MO','MD','AF'],w:'any',mins:5,label:'Hum or play one thing',text:"If you play an instrument, play one thing you know well — slowly, with attention. If you don't, hum something. Making sound with your body reconnects the creative self in a way that is accessible even when depleted and everything else feels distant."},
  {e:'depleted',a:'creativity',t:['LN','EV','NI'],w:'any',mins:5,label:'Save creative inspiration',text:"Spend 5 minutes saving things that interest you — images, articles, sounds, videos — into a folder you'll return to when creative energy is higher. Curating inspiration is a legitimate creative act. The creative work begins with what you pay attention to."},

  // ── CREATIVITY · LOW ─────────────────────────────────────────────────────
  {e:'low',a:'creativity',t:['MO','MD','AF','EV'],w:'any',mins:20,label:'Free writing',text:"Set a timer for 20 minutes and write without stopping — no editing, no reviewing, no judging. Whatever comes. The inner critic loses power when the pen doesn't stop moving. Low energy is often when the most honest creative writing comes out."},
  {e:'low',a:'creativity',t:['MO','MD','AF'],w:'any',mins:15,label:'Sketch ideas',text:"Spend 15 minutes sketching rough ideas for a creative project — wireframes, thumbnails, concept maps, visual notes. You're not making anything finished; you're finding the shape of something. Rough and quick is exactly right at this stage."},
  {e:'low',a:'creativity',t:['MO','MD','AF','EV'],w:'any',mins:20,label:'Practise your craft slowly',text:"Spend 20 minutes doing slow, low-pressure practice of your creative skill — play scales, paint a small corner of something, write a paragraph, code a tiny function. Low-energy practice builds the muscle memory that high-energy sessions run on."},
  {e:'low',a:'creativity',t:['EV','NI'],w:'any',mins:15,label:'Curate an inspiration folder',text:"Spend 15 minutes deliberately curating creative inspiration — images, quotes, sounds, references. A well-organised inspiration folder is infrastructure for creative work. The curation itself trains your eye and develops taste over time."},
  {e:'low',a:'creativity',t:['MO','MD','AF'],w:'any',mins:20,label:'Edit existing work',text:"Return to something you created before and spend 20 minutes editing, improving, or refining it. Editing is less energetically demanding than generating and is often the difference between decent work and work you're proud of."},
  {e:'low',a:'creativity',t:['MO','MD','AF'],w:'any',mins:15,label:'Study work you admire',text:"Spend 15 minutes closely studying creative work you admire — analyse what makes it work, what decisions were made, what you would borrow. Deliberate study of excellent work is one of the most direct paths to developing your own creative sensibility."},
  {e:'low',a:'creativity',t:['MO','MD','AF'],w:'any',mins:20,label:'Variation exercise',text:"Take something you've created and make three variations of it — different approach, different medium, different constraint. Variation practice builds creative range and often surfaces ideas more interesting than the original."},
  {e:'low',a:'creativity',t:['MO','MD','AF'],w:'any',mins:15,label:'Write to a prompt',text:"Find a creative writing or artistic prompt online and respond to it for 15 minutes without overthinking your approach. Constraints and prompts remove the blank page problem and often produce creative work that surprises you with where it goes."},
  {e:'low',a:'creativity',t:['EV','NI'],w:'any',mins:20,label:'Revisit an unfinished project',text:"Open a creative project you abandoned and spend 20 minutes with it — don't try to finish it, just reconnect with what you were trying to make. Unfinished work often feels impossible; revisiting it often reveals it was 70% of the way there all along."},
  {e:'low',a:'creativity',t:['MO','MD','AF'],w:'any',mins:15,label:'Photograph or observe',text:"Spend 15 minutes looking at the world as a photographer or visual artist would — framing, light, texture, unexpected compositions. You don't need to take photos. The practice of looking with creative attention is itself a creative act."},
  {e:'low',a:'creativity',t:['MO','MD','AF'],w:'any',mins:20,label:'Read creatively',text:"Read something in your creative domain — fiction if you're a writer, design books if you're a designer, technical work if you're in a craft. Reading as a practitioner — noting what works and why — is a form of creative training."},
  {e:'low',a:'creativity',t:['EV','NI'],w:'any',mins:15,label:'Organise your creative space',text:"Spend 15 minutes organising the space where you create — physical or digital. Clean tables, organised files, clear brushes, a tidy desktop. The environment of creative work has a direct effect on the quality and comfort of the work done in it."},

  // ── CREATIVITY · MEDIUM ──────────────────────────────────────────────────
  {e:'medium',a:'creativity',t:['MO','MD','AF'],w:'any',mins:45,label:'Focused creative session',text:"Block 45 minutes for a focused creative session on your primary project. Medium energy is the sweet spot for creative work — enough fuel for sustained focus, without the scattered high-energy restlessness that can actually impede craft."},
  {e:'medium',a:'creativity',t:['MO','MD','AF'],w:'any',mins:30,label:'Complete a creative unit',text:"Identify the smallest complete unit of your current creative project and spend 30 minutes finishing it. A complete scene, a complete design element, a complete function, a complete verse. Finishing anything produces the momentum to continue."},
  {e:'medium',a:'creativity',t:['MO','MD','AF'],w:'any',mins:35,label:'Creative problem-solving',text:"Pick the single most creatively stuck part of your current project and spend 35 minutes exploring it from different angles — write about what you're trying to do, sketch alternatives, look at how others have solved similar problems. Being stuck is solvable."},
  {e:'medium',a:'creativity',t:['LN','NI'],w:'any',mins:5,label:'Rest, then create tomorrow',text:"Creative work done past midnight tends to lose the clarity and judgment that make it good. Save your energy for tomorrow's session. Sleep is when creative connections actually form — overnight incubation is a real phenomenon that requires real sleep."},
  {e:'medium',a:'creativity',t:['MO','MD','AF'],w:'any',mins:30,label:'Deliberate practice',text:"Spend 30 minutes in focused practice on the specific skill within your craft that most needs development right now. Not general practice — targeted work on the weakest point. Deliberate practice on creative skills compounds as directly as on any other."},
  {e:'medium',a:'creativity',t:['MO','MD','AF'],w:'any',mins:40,label:'Research and apply',text:"Spend 20 minutes researching a specific technique or approach relevant to your project, then spend 20 minutes immediately applying it. The research-application cycle prevents the common trap of consuming creative theory without ever putting it to use."},
  {e:'medium',a:'creativity',t:['MO','MD','AF'],w:'any',mins:35,label:'Experiment with constraints',text:"Set a creative constraint — a word limit, a time limit, a medium restriction, a specific rule — and create something within it. Constraints consistently produce more interesting creative work than unlimited freedom, across almost every creative domain."},
  {e:'medium',a:'creativity',t:['MO','MD','AF'],w:'any',mins:30,label:'Get feedback and revise',text:"Share something you've created with one trusted person and genuinely listen to their response. Then spend 20 minutes making revisions based on the most useful feedback. Feedback loops are how creative work becomes excellent rather than just personal."},
  {e:'medium',a:'creativity',t:['MO','MD','AF'],w:'any',mins:45,label:'Commit to the page',text:"Open your creative project and commit to producing for the full 45 minutes — no switching to other apps, no stopping to consume, no self-editing before a full draft exists. Volume of output in drafts produces quality in revisions."},
  {e:'medium',a:'creativity',t:['MO','MD','AF'],w:'any',mins:30,label:'Cross-disciplinary input',text:"Spend 30 minutes absorbing work from a creative discipline different from your own — music if you're a visual artist, visual art if you're a writer, architecture if you're a musician. Cross-disciplinary input expands your creative range in ways staying in-domain cannot."},
  {e:'medium',a:'creativity',t:['MO','AF'],w:'out',mins:30,label:'Create outside',text:"Take your creative work outside — a notebook, a sketchpad, your laptop — and work for 30 minutes in a different physical environment. Changing location reliably shifts creative perspective in ways that staying in the same spot prevents."},

  // ── CREATIVITY · HIGH ────────────────────────────────────────────────────
  {e:'high',a:'creativity',t:['MO','MD','AF'],w:'any',mins:90,label:'Major creative sprint',text:"Block 90 minutes for deep creative work on your most ambitious current project. High energy is the condition that makes truly ambitious creative work possible. Don't spend it on revision or admin — spend it on the generation phase at its most demanding."},
  {e:'high',a:'creativity',t:['MO','MD','AF'],w:'any',mins:60,label:'Finish something significant',text:"Take something you've been close to finishing and spend 60 minutes completing it and sending it out into the world. High energy eliminates the self-doubt that causes polished work to stay permanently 'almost ready'. Finish and release."},
  {e:'high',a:'creativity',t:['MO','MD','AF'],w:'any',mins:45,label:'Ambitious new project start',text:"Start a creative project you've been putting off — open the document, make the first marks, write the first lines of code. High energy is exactly what beginnings require. Starting when the conditions feel right is how most important work gets made."},
  {e:'high',a:'creativity',t:['LN','NI'],w:'any',mins:5,label:'Sleep before the creative push',text:"Even at high creative energy, working past midnight compromises the judgment that separates good creative decisions from bad ones. Sleep. Tomorrow, your high energy and your clarity will arrive together — a far better combination than high energy alone."},
  {e:'high',a:'creativity',t:['MO','MD','AF'],w:'any',mins:60,label:'Collaborative creative session',text:"Work on a creative project with another person — co-write, jam, design together, build something jointly. High energy makes collaboration energising rather than draining, and two creative minds in flow together produce things neither would alone."},
  {e:'high',a:'creativity',t:['MO','MD','AF'],w:'any',mins:45,label:'Ship and share your work',text:"Prepare and publish something you've made — post it, send it, submit it, perform it. High energy removes the hesitation that normally holds back creative sharing. The feedback loop of actually sharing work is what makes it grow."},
  {e:'high',a:'creativity',t:['MO','MD','AF'],w:'any',mins:60,label:'Creative exploration session',text:"Spend 60 minutes in pure creative exploration with no output goal — experiment, try new techniques, follow interesting tangents, break your own rules. High-energy play sessions are where creative breakthroughs most often originate."},
  {e:'high',a:'creativity',t:['MO','MD','AF'],w:'any',mins:45,label:'Build the ambitious version',text:"Whatever your current creative project is, spend 45 minutes building the version you'd make if you weren't playing it safe. High energy is for ambition. Make the bolder choice, use the harder technique, write the more vulnerable sentence."},

  // ══════════════════════════════════════════════════════════════════════════
  // ADDITIONAL RECS — HEALTH
  // ══════════════════════════════════════════════════════════════════════════
  {e:'depleted',a:'health',t:['MO','MD','AF'],w:'in',mins:5,label:'Slow indoor stretches',text:"When the weather is keeping you in and energy is low, 5 minutes of slow, careful floor stretches — seated forward fold, gentle twist, reclined butterfly — is a complete act of physical care that asks almost nothing of a depleted body."},
  {e:'depleted',a:'health',t:['MO','MD','AF'],w:'any',mins:3,label:'Posture reset',text:"Wherever you are, sit or stand tall, roll your shoulders back and down, drop your chin slightly, and breathe into your chest for 3 minutes. Poor posture when depleted makes fatigue worse. This small adjustment genuinely helps."},
  {e:'depleted',a:'health',t:['NI','LN'],w:'any',mins:3,label:'Progressive muscle relaxation',text:"Lying down, tense each muscle group for 5 seconds then release — feet, calves, thighs, stomach, hands, arms, shoulders, face. This 3-minute sequence reliably prepares the body for sleep better than just 'trying to relax'."},
  {e:'low',a:'health',t:['EM','MO'],w:'in',mins:15,label:'Indoor morning movement',text:"When it's cold or rainy outside, 15 minutes of gentle indoor movement — slow jogging on the spot, step touches, arm circles, standing marches — maintains circulation and wakes the body without requiring you to face the weather."},
  {e:'low',a:'health',t:['MD'],w:'any',mins:10,label:'Post-lunch walk',text:"Take a 10-minute walk immediately after lunch. This single habit has strong evidence for improving blood sugar regulation, reducing the post-lunch energy dip, and improving afternoon cognitive performance. Short and consistent beats long and occasional."},
  {e:'low',a:'health',t:['EM'],w:'out',mins:10,label:'Sunrise walk',text:"If you're awake early enough, take a 10-minute walk to catch the sunrise or early morning light. Natural light exposure in the first hour after waking has significant effects on sleep quality that night and energy regulation throughout the day."},
  {e:'low',a:'health',t:['AF','EV'],w:'in',mins:20,label:'Rainy day home yoga',text:"A rainy afternoon is perfect for a 20-minute home yoga session. Search 'gentle yoga for low energy' and follow along. The weather gives you permission to stay in and do exactly what your body needs — movement without going anywhere."},
  {e:'low',a:'health',t:['MO','AF'],w:'any',mins:15,label:'Mindful eating practice',text:"Eat your next meal without any screens, sitting at a table, chewing slowly and noticing the food. Mindful eating improves digestion, reduces overeating, and turns a necessary activity into a genuine act of self-care. 15 minutes of real presence."},
  {e:'medium',a:'health',t:['EM','MO'],w:'out',mins:30,label:'Morning run before the day starts',text:"Set your alarm 35 minutes earlier and get a 30-minute run done before the day's demands arrive. Morning runs done consistently have the strongest overall impact on daily energy levels of any exercise timing. Early and done means undisturbed."},
  {e:'medium',a:'health',t:['MO','MD'],w:'in',mins:30,label:'Indoor cycling or rowing',text:"If the weather is keeping you in, 30 minutes on a stationary bike or rowing machine — or a high-energy indoor class — delivers the cardiovascular benefit of outdoor exercise without the weather excuse getting in the way."},
  {e:'medium',a:'health',t:['MD'],w:'any',mins:20,label:'Lunchtime gym visit',text:"A 20-minute gym visit at lunch — quick warm-up, compound lifts, done — is one of the most time-efficient uses of a lunch break. The workout energises the afternoon, the food is earned, and the day's been broken into manageable pieces."},
  {e:'medium',a:'health',t:['EV'],w:'out',mins:30,label:'Evening outdoor workout',text:"If the evening is warm and light, take your workout outside — bodyweight circuit in the park, a run along a route you enjoy, football with whoever's available. Outdoor evening exercise improves mood and sleep quality relative to indoor alternatives."},
  {e:'medium',a:'health',t:['MO','AF'],w:'out',mins:40,label:'Park workout',text:"Take your workout to a park for 40 minutes — use benches for step-ups and dips, trees for pull-ups, grass for bodyweight exercises. Changing your environment changes your relationship to training. The novelty alone increases effort levels."},
  {e:'high',a:'health',t:['EM'],w:'any',mins:45,label:'Pre-dawn training session',text:"Wake up and train before 7am — a 45-minute session completed before the world asks anything of you is psychologically and physically the most empowering way to start a day. High energy + early morning is the rarest and most productive combination."},
  {e:'high',a:'health',t:['MO','AF'],w:'in',mins:60,label:'Intense indoor training',text:"Bad weather doesn't stop serious training. Spend 60 minutes on an intense indoor session — heavy home workout, indoor cycling, HIIT, or a gym session. Conditions don't determine output; your energy level does. This is a high-energy day regardless of the sky."},
  {e:'high',a:'health',t:['MO','AF'],w:'out',mins:75,label:'Long outdoor training',text:"Reserve 75 minutes for proper outdoor training — a long run, a tough cycle route, a sport session. Good weather plus high energy is the best combination for physical performance. Push your personal limits today."},
  {e:'depleted',a:'health',t:['LN','NI'],w:'any',mins:5,label:'Warm bath or shower',text:"Run a warm bath or shower and stay in it for 5-10 minutes. The warmth relaxes muscles, the parasympathetic response reduces cortisol, and the temperature drop afterwards naturally induces sleep. It's recovery disguised as hygiene."},

  // ══════════════════════════════════════════════════════════════════════════
  // ADDITIONAL RECS — WORK
  // ══════════════════════════════════════════════════════════════════════════
  {e:'depleted',a:'work',t:['LN','NI'],w:'any',mins:0,label:'Stop working now',text:"Working while depleted produces output that will need to be redone. The single most productive work decision you can make right now is to stop, sleep, and return to this with a rested mind. Nothing written at midnight at this energy level is worth keeping."},
  {e:'depleted',a:'work',t:['MO','MD'],w:'any',mins:5,label:'Set a do-not-disturb window',text:"Block 2 hours on your calendar as focus time and set your status to do-not-disturb. When depleted, protecting even a small window of uninterrupted time is worth more than being responsive to everything all at once."},
  {e:'low',a:'work',t:['EM','MO'],w:'any',mins:15,label:'Morning brain warm-up',text:"Spend 15 minutes easing into work — review yesterday's notes, skim your task list, open the document you'll work on. Don't start your hardest task first. Warm up your brain like an athlete warms their body. The first 15 minutes shape the rest of the hour."},
  {e:'low',a:'work',t:['AF'],w:'any',mins:20,label:'Afternoon reset',text:"Spend 5 minutes away from your desk, then return and spend 15 minutes deciding exactly what you want to accomplish in the next 90 minutes. Afternoon resets are more productive than white-knuckling through low-energy afternoon periods."},
  {e:'low',a:'work',t:['LN','NI'],w:'any',mins:5,label:'Tomorrow\'s launch pad',text:"Spend 5 minutes before sleep setting up tomorrow's work environment — open the right documents, clear your desktop, leave a note for yourself. Tomorrow-morning you will start with less friction and more momentum."},
  {e:'low',a:'work',t:['MO','MD','AF'],w:'any',mins:15,label:'Respond, don\'t initiate',text:"Spend 15 minutes responding to existing requests rather than initiating new ones. Responses are cognitively lighter than initiations. Low energy is for clearing the queue, not expanding it."},
  {e:'medium',a:'work',t:['EM','MO'],w:'any',mins:30,label:'Morning power hour',text:"The first working hour of the day is cognitively the most valuable for most people. Spend 30 minutes on your single most important task without opening email, Slack, or any communication channel first. Guard this window fiercely."},
  {e:'medium',a:'work',t:['MO','AF'],w:'any',mins:45,label:'Long-term project time',text:"Allocate 45 minutes to something with a long time horizon that never feels urgent enough to prioritise — a strategic plan, a learning project, building infrastructure, a creative initiative. Urgent tasks crowd out important ones unless you explicitly protect time for them."},
  {e:'medium',a:'work',t:['MD'],w:'any',mins:15,label:'Walking meeting',text:"If you have a call that doesn't require a screen, take it outside while walking for 15 minutes. Walking meetings are more energised, often shorter, and systematically better for post-lunch cognitive performance than sitting through the same call at a desk."},
  {e:'medium',a:'work',t:['AF','EV'],w:'any',mins:30,label:'End-of-day completion sprint',text:"Spend 30 minutes in a focused sprint to complete everything you committed to finishing today. Ending the day with completed work — not just busy work — produces the kind of genuine satisfaction that makes the next day feel manageable."},
  {e:'high',a:'work',t:['EM','MO'],w:'any',mins:120,label:'Two-hour deep work session',text:"Block two full hours for deep work — your most difficult and most important task, all notifications off, phone in another room. This is a rare and valuable combination: high energy and enough protected time to achieve something genuinely significant."},
  {e:'high',a:'work',t:['MO','AF'],w:'any',mins:45,label:'Write or present boldly',text:"Make the bold professional move today — write the article with your real opinion, give the presentation that actually says something, send the proposal that you've been second-guessing. High energy is when conviction matches opportunity."},
  {e:'high',a:'work',t:['MO','MD','AF'],w:'any',mins:60,label:'Build something new',text:"Spend 60 minutes creating something that doesn't exist yet — a new framework, a new tool, a new initiative, a new system. High-energy days are when the building blocks of future value get assembled. Don't spend them maintaining existing things."},
  {e:'depleted',a:'work',t:['MO','MD','AF'],w:'any',mins:10,label:'Simplify one process',text:"Find one repetitive work task and spend 10 minutes writing out a simpler way to do it — a template, a shortcut, a checklist. Simplifying processes when depleted is a form of working smarter and leaves a gift for future you."},

  // ══════════════════════════════════════════════════════════════════════════
  // ADDITIONAL RECS — LEARNING
  // ══════════════════════════════════════════════════════════════════════════
  {e:'depleted',a:'learning',t:['EV','NI'],w:'any',mins:10,label:'Watch a documentary clip',text:"Find a 10-minute documentary clip on something you're curious about and let it play. You're not studying — you're just receiving. Passive visual learning at depleted energy is effortless and often surfaces genuine interest you can follow later."},
  {e:'depleted',a:'learning',t:['MO','MD'],w:'any',mins:5,label:'Read one abstract',text:"Find and read one academic abstract or article summary on something in your learning area. You're absorbing a compressed idea without committing to a full read. Five minutes of concept exposure is better than zero."},
  {e:'low',a:'learning',t:['EM','MO'],w:'any',mins:15,label:'Morning learning habit',text:"Build a 15-minute morning learning ritual — same time each day, same topic. Consistency in learning timing is more powerful than occasional long sessions. Small daily input compounds exponentially over months."},
  {e:'low',a:'learning',t:['MD'],w:'any',mins:15,label:'Lunchtime learning',text:"Use 15 minutes of your lunch break for deliberate learning — read an article, watch a lesson, review your notes. Lunchtime learning is one of the most consistent habits of high-performing people across industries."},
  {e:'low',a:'learning',t:['EV'],w:'in',mins:20,label:'Evening course session',text:"Rainy evenings are ideal for online course sessions. Spend 20 minutes completing one lesson or module. The cosy indoor context removes competing options and makes focused learning feel like a natural choice rather than a disciplined one."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:30,label:'Explain to a rubber duck',text:"Sit with a problem or concept you don't fully understand and explain it out loud as if teaching someone — or a rubber duck on your desk. The act of articulating forces you to find the gaps in your own understanding with precision."},
  {e:'medium',a:'learning',t:['MO','MD','AF'],w:'any',mins:40,label:'Build a mind map',text:"Spend 40 minutes building a comprehensive mind map of your current learning topic — from the central concept outward, connecting everything you know. Mind mapping reveals the structure of what you know and makes gaps visually obvious."},
  {e:'medium',a:'learning',t:['EM','MO'],w:'any',mins:25,label:'Morning study before the day',text:"Set your alarm 30 minutes earlier and study before the day starts. Morning learning benefits from sleep-consolidated memory from the night before, and the time before the world makes demands is the quietest, most focused available."},
  {e:'medium',a:'learning',t:['EV'],w:'any',mins:30,label:'Evening problem set',text:"Work through a problem set in the evening on material covered during the day. Evening practice on same-day material is one of the highest-retention study strategies there is — consolidation happens more completely when practice closely follows exposure."},
  {e:'high',a:'learning',t:['MO','MD','AF'],w:'any',mins:60,label:'Master one hard concept',text:"Identify the hardest concept in your current learning and spend 60 minutes achieving genuine mastery of it — multiple sources, worked examples, explained in your own words, applied somewhere real. Don't move on until it's actually clear."},
  {e:'high',a:'learning',t:['MO','AF'],w:'out',mins:30,label:'Learning walk',text:"Take a 30-minute walk while listening to a high-quality educational audio resource — a lecture, an audiobook chapter, a rigorous podcast. High energy means you can engage actively, mentally debating and questioning what you hear rather than just letting it pass."},
  {e:'low',a:'learning',t:['NI','LN'],w:'any',mins:10,label:'Light reading before sleep',text:"Read something educational but not demanding for 10 minutes before sleep — a chapter of a popular non-fiction book, a long-form article. Light pre-sleep reading is retained better than you'd expect, and it's a good alternative to screen time."},
  {e:'depleted',a:'learning',t:['LN','NI'],w:'any',mins:5,label:'Review tomorrow\'s learning goal',text:"Write down one specific thing you want to understand better tomorrow. Just naming the goal before sleep activates subconscious processing overnight. You'll arrive at tomorrow's session with a clearer sense of what you're after."},
  {e:'medium',a:'learning',t:['MD'],w:'any',mins:20,label:'Lunchtime reading sprint',text:"Spend your lunch reading focused material on your learning topic for 20 minutes. Lunchtime is cognitively different from morning and afternoon — often well-suited to reading that requires comprehension but not heavy problem-solving."},

  // ══════════════════════════════════════════════════════════════════════════
  // ADDITIONAL RECS — RELATIONSHIPS
  // ══════════════════════════════════════════════════════════════════════════
  {e:'depleted',a:'relationships',t:['LN','NI'],w:'any',mins:3,label:'Tomorrow\'s connection plan',text:"Before you sleep, name one person you want to reach out to tomorrow and write down specifically what you want to say. Making the plan now means depleted-you has already done the hard part, and tomorrow-you just executes."},
  {e:'low',a:'relationships',t:['MO'],w:'any',mins:10,label:'Morning check-in message',text:"Send a genuine morning check-in to one or two people in your life — 'hope your day goes well', something real about their situation. Starting the day by thinking of others shifts your internal orientation and takes only 10 minutes."},
  {e:'low',a:'relationships',t:['MD'],w:'any',mins:15,label:'Eat with someone',text:"Rather than eating alone at your desk, find someone to share a meal with — a colleague, a housemate, anyone. Shared meals are one of the most ancient and effective relationship-building activities. 15 minutes of food and company."},
  {e:'low',a:'relationships',t:['NI','EV'],w:'any',mins:10,label:'Evening voice message',text:"Send 2-3 people a voice message instead of a text. Voice messages carry warmth, tone, and personality that text strips out. They're also faster to send than typing a long message and more personal to receive."},
  {e:'medium',a:'relationships',t:['MO','MD','AF'],w:'any',mins:20,label:'Professional relationship maintenance',text:"Send thoughtful check-in messages to 3-4 professional contacts you want to maintain — people from previous jobs, mentors, collaborators. Professional relationships fade fastest when busy; they also provide the most unexpected value when maintained."},
  {e:'medium',a:'relationships',t:['EV'],w:'out',mins:45,label:'Evening walk with someone',text:"Invite a friend, partner, or family member to join you for a 45-minute evening walk. The combination of movement, fresh air, and side-by-side conversation produces some of the most natural, honest, and memorable exchanges."},
  {e:'medium',a:'relationships',t:['MO','MD'],w:'any',mins:20,label:'Write a birthday message properly',text:"Find an upcoming birthday in your contacts and write a proper, specific message now — reference something real about the person, a memory, something you appreciate about them. A specific message is 10 times more meaningful than a generic one."},
  {e:'high',a:'relationships',t:['EV','AF'],w:'out',mins:60,label:'Impromptu social plan',text:"Message 3-4 people right now with a spontaneous plan for this evening or weekend. High energy makes the logistics feel effortless and the enthusiasm infectious. The best social memories are often from plans made in the moment by someone with enough energy to follow through."},
  {e:'high',a:'relationships',t:['MO','MD','AF'],w:'any',mins:30,label:'Mentor or support someone',text:"Reach out to someone who could use your perspective, experience, or support and offer it specifically. High energy makes you a better mentor — more patient, more insightful, more generous. Give some of it to someone who would benefit."},
  {e:'low',a:'relationships',t:['MO','MD','AF'],w:'any',mins:10,label:'Send a photo or memory',text:"Go through your photos and find one that features someone you care about, then send it to them with a genuine note about the memory. Photos carry emotional weight that words alone don't. Sending one is a simple act of shared history."},
  {e:'depleted',a:'relationships',t:['MO','MD','AF'],w:'any',mins:3,label:'One emoji reply',text:"If you have messages sitting unanswered, respond to at least one with a genuine response — even brief. Leaving people in silence when depleted is understandable, but one small response keeps the connection alive without requiring more than you have."},
  {e:'medium',a:'relationships',t:['LN','NI'],w:'any',mins:5,label:'Sleep, connect tomorrow',text:"Being truly present for people requires being rested. Send a brief goodnight to whoever expects one and sleep. The relationship you're most neglecting right now might be the one you have with your own need for rest."},
  {e:'low',a:'relationships',t:['EV'],w:'in',mins:20,label:'Rainy evening call',text:"Rainy evenings are perfect for a proper catch-up call. Pick one person you've been meaning to talk to and call them. The cosy indoor weather provides the perfect excuse — and it's all the excuse you need."},

  // ══════════════════════════════════════════════════════════════════════════
  // ADDITIONAL RECS — MINDFULNESS
  // ══════════════════════════════════════════════════════════════════════════
  {e:'depleted',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:3,label:'One-minute breath awareness',text:"Stop whatever you're doing and spend 3 minutes with full attention on your breathing. Notice the temperature of the air, the rise and fall of your chest, the slight pause at the top and bottom of each breath. That's all. Three minutes, fully here."},
  {e:'depleted',a:'mindfulness',t:['MO','AF'],w:'out',mins:5,label:'Step outside and just be',text:"Open the door and stand outside for 5 minutes. No phone, no task. Feel the temperature, listen to the ambient sound, look at the sky. Stepping outside when depleted isn't exercise — it's perspective. The world is still there, beyond the fatigue."},
  {e:'low',a:'mindfulness',t:['EM','MO'],w:'any',mins:10,label:'Morning meditation habit',text:"Build the simplest possible morning mindfulness habit — 10 minutes of guided or silent meditation before you check your phone. This one consistent habit produces measurable changes in stress reactivity, focus, and daily satisfaction within 3-4 weeks."},
  {e:'low',a:'mindfulness',t:['MD'],w:'any',mins:10,label:'Midday mindful pause',text:"At some point around midday, take 10 minutes away from screens and tasks — sit, breathe, and let yourself arrive in the middle of the day. The midday pause is one of the most underused and highest-value mindfulness practices for working people."},
  {e:'low',a:'mindfulness',t:['EV'],w:'in',mins:20,label:'Indoor mindful evening',text:"When the weather keeps you in this evening, use it as a gift. Spend 20 minutes in a mindfulness practice you wouldn't normally have time for — longer journalling, a meditation you've been putting off, deep reading without distraction."},
  {e:'medium',a:'mindfulness',t:['MO'],w:'any',mins:20,label:'Morning pages',text:"Write three pages of stream-of-consciousness in the morning, before doing anything else. This practice — from Julia Cameron's The Artist's Way — reliably clears mental clutter, surfaces creative ideas, and creates a quality of internal quiet that lasts for hours."},
  {e:'medium',a:'mindfulness',t:['AF'],w:'out',mins:25,label:'Mindful park sit',text:"Go to a park and sit on a bench for 25 minutes with your phone in your bag. Watch the world, notice your thoughts without following them, breathe the outdoor air. Intentional stillness in a natural setting is one of the most restorative mindfulness practices available."},
  {e:'medium',a:'mindfulness',t:['EV','NI'],w:'any',mins:25,label:'Evening digital sunset',text:"Put all screens away 25 minutes earlier than usual and spend the time in mindful quiet — reading, stretching, or just sitting. Building a consistent digital sunset habit produces measurable improvements in sleep quality within one week."},
  {e:'medium',a:'mindfulness',t:['MO','AF'],w:'any',mins:30,label:'Focused attention meditation',text:"Spend 30 minutes on focused attention meditation — choose one object of attention (breath, sound, sensation) and return to it every time the mind wanders. This form of practice specifically strengthens the neural circuits associated with sustained focus."},
  {e:'high',a:'mindfulness',t:['MO','AF'],w:'out',mins:45,label:'Walking meditation outside',text:"Do a 45-minute walking meditation outside — slow walking, full attention on each step, each breath, each sensory experience. High energy allows you to maintain the quality of attention required for this practice over an extended period. Move slowly and with full presence."},
  {e:'high',a:'mindfulness',t:['MO','MD','AF'],w:'any',mins:30,label:'Compassion and boundaries',text:"Spend 30 minutes in a reflective practice on where your boundaries are out of alignment — where you're giving beyond your genuine capacity, where resentment has been building, where 'yes' means 'no' to yourself. High energy is when you can face these truths clearly."},
  {e:'high',a:'mindfulness',t:['MO','AF'],w:'any',mins:60,label:'Full presence day design',text:"Spend 60 minutes intentionally designing today to be fully present in everything — planned phone-free windows, a mindful meal, a conversation without distraction, a walk without headphones. High-energy days deserve the quality of attention that makes them memorable."},
  {e:'low',a:'mindfulness',t:['LN','NI'],w:'any',mins:10,label:'Overthinking release',text:"If your mind is running with thoughts late at night, spend 10 minutes writing them all down — every worry, every task, every thought loop. Once externalised on paper, your brain knows it doesn't have to hold them anymore. Often the best sleep aid available."},
  {e:'depleted',a:'mindfulness',t:['MD'],w:'any',mins:5,label:'Mindful lunch',text:"Eat your midday meal without any screens, phones, or distractions for 5 minutes. Just eat, just taste, just notice. A mindful midday moment is a small recalibration available within the structure of something you were already going to do."},

  // ══════════════════════════════════════════════════════════════════════════
  // ADDITIONAL RECS — CREATIVITY
  // ══════════════════════════════════════════════════════════════════════════
  {e:'depleted',a:'creativity',t:['EV','NI'],w:'in',mins:10,label:'Rainy evening creating',text:"Rainy evenings and depleted energy have produced some of history's most honest creative work. Open a notebook, let words or images come without pressure, and see what arrives. You're not making something good — you're making something real."},
  {e:'depleted',a:'creativity',t:['MO','MD'],w:'any',mins:5,label:'Collect one idea',text:"Write down one creative idea — however half-formed, however ridiculous, however far from ready. Ideas that aren't written down disappear. Depleted days still produce ideas; they just produce fewer of them. Catch this one before it goes."},
  {e:'low',a:'creativity',t:['EV'],w:'in',mins:20,label:'Cosy creative evening',text:"When the weather is bad and energy is low, create something low-stakes and pleasurable — draw without an objective, write without an audience, play without structure. The low-stakes creative evening is where ideas incubate that surface later as something real."},
  {e:'low',a:'creativity',t:['EM','MO'],w:'any',mins:15,label:'Morning creative warm-up',text:"Before you do anything productive or responsive, spend 15 minutes in a free creative warm-up — freewrite, sketch, hum, noodle on an instrument. Creative warm-ups, like physical ones, produce better-quality output in the session that follows."},
  {e:'low',a:'creativity',t:['MD'],w:'any',mins:15,label:'Lunchtime creative input',text:"Use 15 minutes of lunch to consume something creatively stimulating — a great essay, a piece of music, a short film. Input at low energy is a legitimate creative act. You're filling the well that output draws from."},
  {e:'medium',a:'creativity',t:['EM','MO'],w:'any',mins:30,label:'Morning creative session',text:"Many of the best creative practitioners protect the first 30 minutes of the day for creative work, before the cognitive load of the day accumulates. Spend this window purely creating, before reading email, checking news, or talking to anyone."},
  {e:'medium',a:'creativity',t:['EV'],w:'in',mins:30,label:'Evening creative practice',text:"Reserve 30 minutes this evening for deliberate creative practice. Evening creativity benefits from the day's processed experience and the relative quiet as demands decrease. This is when a lot of meaningful creative work quietly gets done."},
  {e:'medium',a:'creativity',t:['AF'],w:'any',mins:25,label:'Unstick one creative block',text:"Identify the most creatively stuck moment in your current project and spend 25 minutes specifically on that one thing — draw it from a different angle, write around it, talk it through with someone, or simply write 'why is this hard' and answer honestly."},
  {e:'medium',a:'creativity',t:['MD'],w:'any',mins:20,label:'Midday creative reset',text:"Step away from whatever you've been doing and spend 20 minutes in pure creative mode — not your primary project, just free creative play. Midday creative resets often unlock afternoon productivity by giving the analytical brain a rest and the creative brain a run."},
  {e:'high',a:'creativity',t:['EM','MO'],w:'any',mins:60,label:'Golden hour creative work',text:"Many creatives do their best work in the first focused hours of the day. Spend 60 minutes creating at your highest level before the day's complexity arrives. High energy plus morning clarity is the combination that produces the creative work you'll be proudest of."},
  {e:'high',a:'creativity',t:['EV'],w:'any',mins:45,label:'Evening creative push',text:"Spend 45 minutes in a focused evening creative session before winding down. High energy in the evening is rarer than morning energy — use it with intention on work that matters to you, not on passive consumption."},
  {e:'high',a:'creativity',t:['AF'],w:'out',mins:45,label:'Create in a new location',text:"Take your creative work somewhere completely different — a café, a park, a library, a friend's kitchen. A new environment with high energy produces creative output that feels measurably different to what you make in your usual space."},
  {e:'low',a:'creativity',t:['NI','LN'],w:'any',mins:10,label:'Capture before sleep',text:"Keep a notebook by your bed and spend 10 minutes writing down whatever creative fragments, ideas, or images are floating in your mind before sleep. The hypnagogic state between waking and sleeping is one of the most creative mental states available."},
  {e:'depleted',a:'creativity',t:['LN','NI'],w:'any',mins:5,label:'Tomorrow\'s creative seed',text:"Write one sentence — the seed of something you might make tomorrow when energy returns. One sentence is enough. Plant it now, sleep on it, and find it waiting for you in the morning when you have more to give."},

  // ══════════════════════════════════════════════════════════════════════════
  // TIME-SPECIFIC LATE NIGHT RECS (all areas, any energy at LN)
  // ══════════════════════════════════════════════════════════════════════════
  {e:'medium',a:'health',t:['LN'],w:'any',mins:5,label:'You need sleep now',text:"Medium energy at this hour is a sign your body is running on cortisol, not genuine fuel. The health investment that dwarfs everything else available right now is sleep. Put your phone down, close your eyes, and let the recovery begin."},
  {e:'medium',a:'work',t:['LN'],w:'any',mins:5,label:'Shutdown and sleep',text:"Work produced after midnight at medium energy will almost certainly need to be redone or refined tomorrow. The productive move is to shut down properly and sleep. Tomorrow's rested session is worth more than tonight's depleted one."},
  {e:'medium',a:'learning',t:['LN'],w:'any',mins:5,label:'Sleep to consolidate',text:"Sleep is when the brain consolidates what you learned today. Staying up to study further past this point reduces retention, not increases it. The best learning investment right now is sleep. The material will be clearer in the morning."},
  {e:'medium',a:'relationships',t:['LN'],w:'any',mins:3,label:'Send one goodnight message',text:"Send a brief goodnight to whoever expects one, then put your phone down and sleep. Well-rested you is a better friend, partner, and family member than late-night you. The best relationship investment tonight is taking care of yourself."},
  {e:'medium',a:'mindfulness',t:['LN'],w:'any',mins:8,label:'Midnight body scan to sleep',text:"Lie down and slowly scan through your body from feet to head, releasing tension with each exhale. This isn't a meditation session — it's a sleep induction practice. Medium energy at midnight needs to become rest, not mindfulness projects."},
  {e:'medium',a:'creativity',t:['LN'],w:'any',mins:3,label:'Note the idea, then sleep',text:"If there's a creative idea alive in your head right now, write it down in three sentences, then close the notebook. Ideas are better explored with a rested mind. Plant the seed tonight and let sleep do the creative work of incubation."},
  {e:'high',a:'health',t:['LN'],w:'any',mins:5,label:'High energy, wrong time',text:"Your energy is high but it's past midnight — this is the pattern that erodes health over time. The most important health decision tonight is to resist the urge to use this energy and sleep instead. Protect tomorrow's performance."},
  {e:'high',a:'work',t:['LN'],w:'any',mins:5,label:'Stop — protect tomorrow',text:"High energy at midnight is a trap. The next two hours of work will cost more than they produce because the quality of judgment degrades significantly after midnight. Shut down, sleep, and let tomorrow's session run on full capacity."},
  {e:'high',a:'learning',t:['LN'],w:'any',mins:5,label:'Sleep for memory formation',text:"High energy late at night often comes with reduced awareness of cognitive limits. Memory consolidation — the actual learning — requires sleep. What you study tonight won't be retained without it. Sleep is the completion of the learning cycle."},
  {e:'high',a:'relationships',t:['LN'],w:'any',mins:3,label:'Sleep to be present tomorrow',text:"The people who matter to you deserve the version of you that had enough sleep. Send a goodnight, put your phone away, and invest in being genuinely present for them tomorrow. That's the relationship act with the highest return right now."},
  {e:'high',a:'mindfulness',t:['LN'],w:'any',mins:5,label:'Mindful goodnight',text:"High energy at midnight isn't sustainable — it's adrenaline, not vitality. The most mindful thing you can do right now is recognise this, set your phone aside, and practise the discipline of choosing rest over stimulation. Good night."},
  {e:'high',a:'creativity',t:['LN'],w:'any',mins:3,label:'Park the idea, sleep',text:"Write the creative idea down in three sentences maximum, then put it away. Ideas seeded at midnight and slept on produce more interesting work than ideas pursued at midnight when judgment is compromised. Trust the sleep to develop it."},

  // ══════════════════════════════════════════════════════════════════════════
  // WEATHER-SPECIFIC RECS (cold/rainy vs clear/hot)
  // ══════════════════════════════════════════════════════════════════════════
  {e:'medium',a:'health',t:['MO','MD','AF'],w:'in',mins:25,label:'Rainy day home cardio',text:"It's bad outside — perfect excuse to try a full 25-minute home cardio session. Jumping jacks, high knees, burpees, mountain climbers, inchworms. No gym, no weather dependency, no commute. The rain makes the indoor session feel cosy."},
  {e:'medium',a:'health',t:['MO','AF'],w:'out',mins:35,label:'Clear weather outdoor training',text:"Beautiful weather and medium energy — this is the combination that makes outdoor training feel effortless. Head outside for 35 minutes: a run, a park workout, a cycle. Good weather is a finite resource; use it."},
  {e:'high',a:'health',t:['MO','AF'],w:'in',mins:50,label:'Intense indoor session',text:"Don't let the rain be an excuse. You have high energy and that doesn't change based on the weather. Spend 50 minutes on the most intense home workout you can structure — AMRAP circuits, supersets, maximum effort. Conditions don't determine output."},
  {e:'low',a:'health',t:['MO','AF'],w:'in',mins:15,label:'Rainy day gentle movement',text:"When rain keeps you in and energy is low, 15 minutes of gentle indoor movement — slow yoga, careful stretching, light pilates — is the right pairing. Don't fight the energy or the weather; move gently within both."},
  {e:'low',a:'mindfulness',t:['EV','AF'],w:'in',mins:20,label:'Rain as meditation backdrop',text:"Sit somewhere you can hear the rain and let it become the focus of your meditation for 20 minutes. Rain is one of the most naturally conducive backdrops for mindfulness practice — a consistent, calming, environmental anchor for the wandering mind."},
  {e:'medium',a:'mindfulness',t:['MO','AF'],w:'in',mins:25,label:'Cosy indoor practice day',text:"Bad weather creates the perfect indoor mindfulness conditions. Spend 25 minutes in a candle-lit or low-light meditation session — longer than usual, unhurried, with nowhere you need to be. Let the rainy day be a gift of permission to go inward."},
  {e:'low',a:'creativity',t:['AF','EV'],w:'in',mins:25,label:'Rainy afternoon creating',text:"There's a reason rainy afternoons feel creative — they remove the environmental option of going out. Spend 25 minutes making something deliberately: writing, drawing, playing, building. Let the rain be your creative companion."},
  {e:'medium',a:'creativity',t:['AF','EV'],w:'in',mins:40,label:'Rain-day deep creative session',text:"A sustained rainy afternoon is rare. Use it: 40 minutes on your most important creative work, with the sound of rain as a backdrop. Weather that keeps you in creates unbroken creative time that sunny afternoons rarely allow."},
  {e:'medium',a:'learning',t:['AF','EV'],w:'in',mins:35,label:'Rainy afternoon study session',text:"Bad weather is a natural study incentive. Spend 35 minutes in a structured study session with a warm drink, your materials, and no outdoor alternative. Let the rain validate the choice to sit still and actually learn something."},
  {e:'high',a:'health',t:['MO','AF'],w:'out',mins:60,label:'Seize the good weather',text:"Clear, good weather and high energy simultaneously is one of the rarer combinations of conditions. Spend 60 minutes training outdoors — running, cycling, sport, a long hike. Don't waste this pairing on indoor alternatives."},
  {e:'medium',a:'work',t:['MO','AF'],w:'in',mins:40,label:'Productive indoor work day',text:"Cold or rainy weather actually improves focus by reducing the temptation to be elsewhere. Spend 40 minutes in the deepest work session the weather conditions and your medium energy will allow. Sometimes the best working conditions are the ones that keep you in."},
  {e:'low',a:'work',t:['AF','EV'],w:'in',mins:20,label:'Rainy afternoon admin',text:"Let the rain handle your decision about going out. Spend 20 minutes clearing work admin — filing, responding, updating lists. Low energy plus indoor conditions is the exact combination well-suited to tasks that need doing but not deep focus."},

  // ══════════════════════════════════════════════════════════════════════════
  // EARLY MORNING SPECIFIC (EM slot, all areas)
  // ══════════════════════════════════════════════════════════════════════════
  {e:'low',a:'mindfulness',t:['EM'],w:'any',mins:10,label:'Quiet morning before the day',text:"The early morning, before notifications begin and the day makes its demands, is the most reliable mindfulness window in the day. Sit in the quiet for 10 minutes — no phone, no agenda — and arrive at the day before it arrives at you."},
  {e:'low',a:'work',t:['EM'],w:'any',mins:10,label:'Morning intention for work',text:"Before opening any communication channel, spend 10 minutes deciding what you want to actually accomplish today — one main thing, two supporting things. Set the agenda before the inbox sets it for you. This one habit changes the shape of the whole day."},
  {e:'medium',a:'health',t:['EM'],w:'out',mins:20,label:'Pre-day outdoor movement',text:"Morning exercise before the workday consistently outperforms planned evening exercise in adherence, mood lift, and metabolic benefit. 20 minutes outside before 8am is worth 40 minutes planned for after work."},
  {e:'medium',a:'learning',t:['EM'],w:'any',mins:20,label:'Pre-email morning study',text:"Study for 20 minutes before you open any communication app. Your brain is most receptive to new information in the first hour of waking. Protect this window from reactive tasks and use it for something that builds your capabilities."},
  {e:'high',a:'creativity',t:['EM'],w:'any',mins:30,label:'Pre-dawn creative work',text:"The hours before the rest of the world wakes are some of the most productive creative windows available — silent, unhurried, and free from interruption. Spend 30 minutes creating at the day's very start. It will feel like a different gear."},
  {e:'high',a:'work',t:['EM'],w:'any',mins:45,label:'Morning high-energy work block',text:"High energy in the early morning is one of the rarest and most valuable productive conditions. Spend 45 minutes on your most cognitively demanding work before the day generates any friction. This window, used well, produces disproportionate output."},
  {e:'depleted',a:'mindfulness',t:['EM'],w:'any',mins:5,label:'Slow morning start',text:"When you wake depleted, don't immediately reach for your phone. Spend 5 minutes in bed or seated, breathing slowly, before the day's inputs arrive. A slow start when depleted preserves what little energy you have for things that actually matter."},
  {e:'low',a:'relationships',t:['EM'],w:'any',mins:5,label:'Morning message to someone',text:"Send one warm morning message before your day starts — to someone you love, a friend you've been thinking about, family far away. Starting the day by thinking of others shifts your orientation before the day's demands make it harder."},

  // ══════════════════════════════════════════════════════════════════════════
  // HOT WEATHER SPECIFIC RECS
  // ══════════════════════════════════════════════════════════════════════════
  {e:'medium',a:'health',t:['EM'],w:'out',mins:30,label:'Beat the heat: early workout',text:"When it's going to be hot today, the window for outdoor training is early morning. Spend 30 minutes training outside before 8am before the heat builds. Waiting for later means waiting for conditions that won't come until tomorrow morning."},
  {e:'medium',a:'health',t:['MO','MD'],w:'in',mins:30,label:'Hot day indoor training',text:"It's too hot for intense outdoor exercise. Take the workout inside — gym, pool, or a well-ventilated home session. Adjust the intensity slightly to account for the temperature, and stay well hydrated throughout. Heat is a serious variable."},
  {e:'low',a:'health',t:['MD','AF'],w:'in',mins:10,label:'Hot day hydration and rest',text:"When it's very hot and energy is low, the highest-priority health action is hydration and rest in a cool space. Drink a full glass of water now, find somewhere cool, and give your body the recovery it needs before pushing further."},
  {e:'high',a:'health',t:['EM'],w:'out',mins:45,label:'Sunrise training session',text:"Get out before the heat arrives and train at sunrise. The combination of cool air, morning light, high energy, and the quiet of early morning produces some of the best physical training sessions available. Set your alarm tonight."},
  {e:'medium',a:'mindfulness',t:['MD','AF'],w:'in',mins:20,label:'Cool indoor midday pause',text:"When it's hot outside, a cool indoor midday mindfulness practice is a genuine refuge. Sit in a cool room, breathe slowly, and let the external heat contrast with the internal stillness you're cultivating. Temperature can be part of the practice."},

  // ══════════════════════════════════════════════════════════════════════════
  // MIDDAY SPECIFIC RECS (MD slot)
  // ══════════════════════════════════════════════════════════════════════════
  {e:'medium',a:'work',t:['MD'],w:'any',mins:15,label:'Mid-day priority reset',text:"Stop at midday and spend 15 minutes reviewing the day — what's been completed, what matters most in the afternoon, what can be deprioritised. A deliberate midday reset prevents the afternoon from becoming reactive instead of intentional."},
  {e:'medium',a:'mindfulness',t:['MD'],w:'any',mins:10,label:'Lunchtime mindfulness break',text:"Take a proper mindful lunch break — eat slowly, without screens, noticing each bite. The midday mindful pause is one of the highest-impact and most underused practices in working life. Ten minutes of genuine presence between morning and afternoon."},
  {e:'low',a:'health',t:['MD'],w:'any',mins:10,label:'Midday posture and movement',text:"Get up from your desk at midday, roll your shoulders, stretch your spine, walk for 3 minutes. Sitting still for a full morning without a break is physiologically damaging. Ten minutes of movement undoes much of the morning's accumulated tension."},
  {e:'medium',a:'learning',t:['MD'],w:'any',mins:20,label:'Midday reading over lunch',text:"Eat your lunch slowly and read for 20 minutes — a book, a long article, something substantive. Midday reading is cognitively different from morning or evening reading and is often where surprising connections between ideas emerge."},
  {e:'high',a:'work',t:['MD'],w:'any',mins:30,label:'Midday sprint on one thing',text:"Identify the one thing that, if completed by 2pm, would make the whole day successful. Spend 30 minutes in a focused sprint to finish it. High energy at midday is rarer than morning energy — don't spend it on email."},
  {e:'low',a:'mindfulness',t:['MD'],w:'out',mins:10,label:'Sunny lunch break outside',text:"If it's nice outside, take your lunch break outdoors — even 10 minutes in natural light at midday has measurable effects on afternoon mood, alertness, and the quality of sleep that night. The sun at noon is the most powerful environmental regulator."},
  {e:'medium',a:'health',t:['MD'],w:'any',mins:20,label:'Lunchtime active break',text:"Don't eat at your desk. Take a 20-minute lunch break that includes both eating and movement — even a 10-minute walk before or after eating. This is one of the most consistent productivity habits across high-performing professionals."},

  // ══════════════════════════════════════════════════════════════════════════
  // EVENING SPECIFIC RECS (EV slot)
  // ══════════════════════════════════════════════════════════════════════════
  {e:'medium',a:'health',t:['EV'],w:'in',mins:20,label:'Evening home workout',text:"When evenings keep you indoors, 20 minutes of home exercise — circuits, stretching, yoga — is a complete physical investment in your health. The effort required to start is the only barrier. Cross it and you'll finish feeling better than you started."},
  {e:'low',a:'learning',t:['EV'],w:'any',mins:15,label:'Evening review',text:"Spend 15 minutes in the evening reviewing what you covered today — flip through notes, recall key ideas, jot down what you want to revisit. Evening review dramatically improves next-day retention and costs almost nothing at low energy."},
  {e:'medium',a:'relationships',t:['EV'],w:'out',mins:30,label:'Evening with someone',text:"The evening is prime time for relationship investment. Make concrete plans to spend 30 minutes with someone you care about — outside if the weather allows. Evening connection time, done consistently, is the single most effective relationship maintenance practice."},
  {e:'high',a:'creativity',t:['EV'],w:'any',mins:45,label:'Evening creative flow',text:"High creative energy in the evening is valuable — the day's experience has loaded your subconscious with material, and the quieting of the world reduces interference. Spend 45 minutes in a dedicated creative session and see what emerges."},
  {e:'low',a:'mindfulness',t:['EV'],w:'any',mins:15,label:'Evening journalling',text:"Spend 15 minutes at day's end writing about how it actually went — not just what happened, but how you felt, what mattered, what you want to carry forward. Evening journalling is the practice that converts daily experience into genuine self-knowledge over time."},
  {e:'medium',a:'work',t:['EV'],w:'any',mins:20,label:'End-of-day wrap-up',text:"Spend 20 minutes on a proper work wrap-up — close open items, update your task list, set tomorrow's priorities, and write a one-paragraph status note for any key projects. A clean daily close makes tomorrow's start 30% easier."},
  {e:'high',a:'health',t:['EV'],w:'out',mins:40,label:'Evening outdoor activity',text:"Good evening weather plus high energy is a pairing that calls for outdoor activity. Spend 40 minutes doing something physical outside — a run, a cycle, a sport, a group fitness session. Evening outdoor exercise is one of the day's best-kept productive habits."},

  // ══════════════════════════════════════════════════════════════════════════
  // NIGHT SPECIFIC RECS (NI slot, 8-10pm)
  // ══════════════════════════════════════════════════════════════════════════
  {e:'medium',a:'mindfulness',t:['NI'],w:'any',mins:15,label:'Night wind-down ritual',text:"Begin winding down at 9pm with a 15-minute mindfulness practice — gentle breathing, a body scan, or slow journalling. A consistent wind-down ritual starting before 10pm is one of the most evidence-supported sleep improvement interventions available."},
  {e:'medium',a:'learning',t:['NI'],w:'any',mins:15,label:'Pre-sleep review',text:"Spend 15 minutes at 9pm reviewing your notes or reading gently in your learning area — no new, demanding material, just reinforcing what you know. Then close everything and let sleep do its consolidation work. This is one of the highest-return learning practices."},
  {e:'medium',a:'creativity',t:['NI'],w:'any',mins:15,label:'Evening creative notes',text:"Spend 15 minutes at 9pm writing creative notes — ideas, images, fragments, questions. Then stop and sleep. The hour before sleep is one of the most creative mental states; capturing ideas at this time and sleeping on them often produces morning clarity you didn't expect."},
  {e:'high',a:'work',t:['NI'],w:'any',mins:10,label:'Wrap up and protect tomorrow',text:"If you have high energy tonight, the most strategic work decision is to wrap up properly — clear notes, set tomorrow's priorities, close your laptop — and sleep. Tomorrow's high energy with a clear plan is worth more than tonight's session running into midnight."},
  {e:'low',a:'health',t:['NI'],w:'any',mins:10,label:'Pre-sleep recovery',text:"Spend 10 minutes at 9pm on pre-sleep recovery — light stretching, 5 minutes of slow breathing, a warm drink. These small investments in sleep quality compound significantly over weeks. The quality of your sleep is a direct health metric."},
  {e:'medium',a:'relationships',t:['NI'],w:'any',mins:10,label:'Evening connection wrap-up',text:"Spend 10 minutes before sleep connecting briefly with whoever matters most — a short conversation, a message, expressing appreciation. Ending the day with genuine human connection, even briefly, improves both relationship quality and sleep quality."},
  {e:'low',a:'mindfulness',t:['NI'],w:'any',mins:10,label:'Gratitude before sleep',text:"Write 5 specific things you're grateful for from today before you sleep. Specificity is what activates the gratitude response — 'the conversation with my sister at lunch' beats 'my family'. Do this every night for 3 weeks and measure the change."},

  // ══════════════════════════════════════════════════════════════════════════
  // FINAL BATCH — filling remaining area / energy gaps
  // ══════════════════════════════════════════════════════════════════════════

  // Health extras
  {e:'low',a:'health',t:['MO','AF'],w:'in',mins:20,label:'Home circuit, no excuses',text:"Rain or cold outside is zero reason not to move. Spend 20 minutes on a home circuit — squats, push-ups, sit-ups, lunges, burpees at your own pace. No equipment, no weather dependency. The only barrier is starting."},
  {e:'medium',a:'health',t:['EM'],w:'in',mins:20,label:'Indoor morning session',text:"Bad weather this morning? Do 20 minutes of indoor movement before you do anything else — a short yoga flow, a bodyweight circuit, jumping jacks and stretches. Morning movement before screens is valuable regardless of what's happening outside."},
  {e:'high',a:'health',t:['MD'],w:'any',mins:20,label:'Lunchtime gym hit',text:"Get to a gym for 20 minutes at lunch — a quick full-body circuit, heavy compound sets, or a short intense cardio session. Lunchtime is an underused training window. Twenty sharp minutes beats a skipped evening session every time."},
  {e:'depleted',a:'health',t:['MD'],w:'any',mins:5,label:'Step outside briefly',text:"Even if you can only manage 5 minutes, step outside at midday and stand in the natural light. Midday light exposure helps regulate your circadian rhythm and can provide a small but real lift to depleted energy by signalling your body what time it is."},
  {e:'medium',a:'health',t:['EV'],w:'in',mins:25,label:'Evening stretch and breathe',text:"Spend 25 minutes this evening on a gentle stretch sequence followed by 5 minutes of slow breathing. Evening flexibility and breathwork together is one of the most effective wind-down practices for both physical recovery and improved sleep onset."},
  {e:'high',a:'health',t:['EM'],w:'in',mins:40,label:'Indoor intensity session',text:"Don't let a cold or rainy morning be an excuse. Set up an intense 40-minute indoor session — HIIT, heavy home lifting, high-rep circuits. Your energy level is the variable; weather is not. Go."},

  // Work extras
  {e:'low',a:'work',t:['EM'],w:'any',mins:10,label:'Slow morning ramp-up',text:"Ease into work over 10 minutes — review your notes from yesterday, read one brief thing relevant to your main task, open the document. A slow ramp-up honours low energy while still making forward motion before the urgency of the day takes over."},
  {e:'low',a:'work',t:['EV'],w:'any',mins:15,label:'Prep tomorrow properly',text:"Spend 15 minutes this evening setting up for tomorrow — open the files you'll need, write your first three tasks, clear your desk. Tomorrow morning's you will start with clarity rather than spending energy figuring out where to begin."},
  {e:'medium',a:'work',t:['EM'],w:'any',mins:20,label:'Before-email work block',text:"Complete 20 minutes of focused work on your priority task before opening email for the day. The inbox is a list of other people's priorities. Your work, done first, ensures your own priorities get the best cognitive hours of the day."},
  {e:'high',a:'work',t:['EV'],w:'any',mins:30,label:'Evening high-value push',text:"If you still have high energy in the evening, use the last 30 minutes productively — write, build, create — but set a hard stop time. High-energy evenings are valuable but protecting tomorrow's energy matters as much as using tonight's."},
  {e:'medium',a:'work',t:['MO','MD','AF'],w:'in',mins:40,label:'Bad weather focus day',text:"Cold or rainy days remove the temptation to be elsewhere and are objectively some of the best working conditions available. Spend 40 minutes treating today's weather as a gift of an excuse to sit down and do the work without interruption."},
  {e:'low',a:'work',t:['NI'],w:'any',mins:10,label:'Shutdown ritual',text:"Do a 10-minute work shutdown tonight — update your task list, write tomorrow's top three, close every work application. A consistent shutdown ritual signals your brain that work is done, which measurably improves both sleep quality and next-morning focus."},
  {e:'high',a:'work',t:['EM'],w:'any',mins:60,label:'Sunrise deep work',text:"Use the quietest hours of the day for your most demanding work. 60 minutes before the world wakes up, with high energy, doing your most important task — this combination produces output quality that busy afternoons and distracted evenings cannot match."},

  // Learning extras
  {e:'medium',a:'learning',t:['EV'],w:'in',mins:30,label:'Evening focused study',text:"Spend 30 minutes in a dedicated evening study session while the day's input is still fresh. Evening study on material covered during the day produces significantly better retention than studying at other times. The rain outside makes it easier to stay in and do this."},
  {e:'high',a:'learning',t:['EM'],w:'any',mins:45,label:'Early morning skill work',text:"Do 45 minutes of deliberate skill practice at the start of the day, before reactive tasks accumulate. Morning learning benefits from overnight memory consolidation and the cognitive freshness that follows sleep. Your best learning window is probably right now."},
  {e:'low',a:'learning',t:['EM'],w:'any',mins:10,label:'Morning reading ritual',text:"Read for 10 minutes on your learning topic every morning before picking up your phone. This single habit, done consistently, accumulates 60+ hours of learning per year without ever requiring a dedicated 'study session'."},
  {e:'medium',a:'learning',t:['NI'],w:'any',mins:15,label:'Pre-sleep concept review',text:"At 9pm, spend 15 minutes reviewing your notes on the most important concept you covered today. Close the notes, write down what you remember without looking, then check. This retrieval practice immediately before sleep produces outstanding retention."},
  {e:'depleted',a:'learning',t:['MO','AF'],w:'any',mins:5,label:'Read headlines in your field',text:"Spend 5 minutes scanning headlines or summaries in your field of study — newsletters, Reddit communities, LinkedIn, whatever keeps you current. Passive exposure to the conversation in your area is learning at its least effortful."},
  {e:'high',a:'learning',t:['MD'],w:'any',mins:30,label:'Lunchtime intensive practice',text:"Use your lunch break for 30 minutes of intensive practice — working through problems, building something, writing summaries. Lunchtime intensive sessions are one of the most underused windows for high-quality learning in a working week."},
  {e:'low',a:'learning',t:['MO','MD','AF'],w:'in',mins:15,label:'Rainy day reading',text:"Bad weather is nature's invitation to sit still and read. Spend 15 minutes with your learning material and a hot drink. The environmental context of a rainy day actually enhances the comfort and focus of indoor learning tasks."},

  // Relationships extras
  {e:'medium',a:'relationships',t:['EM'],w:'any',mins:10,label:'Morning message to someone close',text:"Before the day\'s demands arrive, send one thoughtful message to someone important. A morning message that says 'I was thinking about you' costs 5 minutes and registers as a meaningful act of care. Do it before you open your email."},
  {e:'high',a:'relationships',t:['MO','MD'],w:'any',mins:20,label:'Spontaneous kind gesture',text:"Identify something specific you can do for one person in your life right now — not later, now. Order them something, send them something, go to them. High energy is when spontaneous generosity costs least and means most."},
  {e:'low',a:'relationships',t:['EM'],w:'any',mins:5,label:'Good morning message',text:"Send a short, warm message to a few people before your day starts. 'Morning — hope your week is going well.' It costs five minutes and starts several people's days knowing someone was thinking of them. Small habit, real effect."},
  {e:'medium',a:'relationships',t:['NI'],w:'any',mins:10,label:'End the day connected',text:"Before sleep, spend 10 minutes in genuine connection with the person or people closest to you — a real conversation, not phone-scrolling in the same room. How you end the day with the people you love matters to the health of those relationships."},
  {e:'depleted',a:'relationships',t:['MD'],w:'any',mins:3,label:'Quick thoughtful reply',text:"Reply to one message you\'ve been avoiding because you weren\'t sure what to say. Keep it brief and honest: 'Sorry for the slow reply — things have been a lot lately. How are you?' Genuine and brief beats long and never sent."},
  {e:'high',a:'relationships',t:['MO','AF'],w:'any',mins:45,label:'Invest in a struggling relationship',text:"If there is a relationship in your life that has been strained, distant, or neglected, spend 45 minutes giving it genuine attention. Write the message, make the call, arrange the meeting. High energy gives you the emotional capacity to handle the complexity with care."},
  {e:'low',a:'relationships',t:['NI'],w:'any',mins:5,label:'Voice note to someone far away',text:"Record a 2-minute voice note to someone you don't see enough — a parent, an old friend, someone far away. Voice notes cross distance in a way text can't. Sending one tonight costs nothing and could genuinely make someone's tomorrow."},
  {e:'medium',a:'relationships',t:['AF'],w:'out',mins:30,label:'Spontaneous visit or meet-up',text:"If someone lives nearby, message them right now and suggest meeting in the next hour or two — coffee, a walk, anything. Spontaneous plans often produce the best experiences. Medium energy makes the social initiative feel natural rather than forced."},

  // Mindfulness extras
  {e:'high',a:'mindfulness',t:['EM'],w:'any',mins:20,label:'Morning meditation anchor',text:"Meditate for 20 minutes immediately after waking, before your phone. High energy in the morning is the ideal state for a challenging meditation practice — the mind is alert enough for depth without the accumulated distraction of the day's events."},
  {e:'low',a:'mindfulness',t:['EM'],w:'any',mins:10,label:'Slow morning arrival',text:"Before picking up your phone, spend 10 minutes arriving gently into the day — sit, breathe, notice how you feel, set one intention. This pre-phone morning window is the highest-value mindfulness practice for most people, precisely because it comes before anything reactive."},
  {e:'medium',a:'mindfulness',t:['MD'],w:'out',mins:15,label:'Mindful lunch outside',text:"Take your lunch outside on a nice day and eat it with full attention — no phone, no planning, just the food, the air, and the people or nature around you. A mindful outdoor lunch is a genuine midday reset that improves afternoon performance."},
  {e:'medium',a:'mindfulness',t:['NI'],w:'any',mins:15,label:'Evening journalling ritual',text:"Spend 15 minutes journalling before sleep — not about tasks, about experience. What did you notice today? What moved you, frustrated you, surprised you? This reflective practice builds self-knowledge and emotional processing more than almost any other available practice."},
  {e:'high',a:'mindfulness',t:['AF'],w:'out',mins:30,label:'Mindful outdoor time',text:"Spend 30 minutes outside with full presence — no headphones, no phone, no agenda. Walk, sit, observe. High energy is when you can sustain genuine present-moment attention outdoors long enough to reach the quality of stillness that makes nature restorative."},
  {e:'depleted',a:'mindfulness',t:['AF'],w:'any',mins:5,label:'Afternoon breathing reset',text:"At some point this afternoon, stop whatever you\'re doing and take 5 slow, deliberate breaths. Mid-afternoon is when tension accumulates most invisibly. A 5-breath reset costs nothing and recalibrates your nervous state before it gets worse."},
  {e:'low',a:'mindfulness',t:['AF'],w:'any',mins:10,label:'Afternoon body check-in',text:"Pause in the afternoon and do a brief physical check-in — notice where tension has accumulated since morning, take 5 slow breaths into tight areas, adjust your posture. Low energy afternoons benefit from this kind of gentle self-attunement."},
  {e:'high',a:'mindfulness',t:['NI'],w:'any',mins:15,label:'Intentional wind-down',text:"High energy at night can make winding down feel wasteful. Spend 15 minutes in a deliberate transition practice — write 3 reflections from the day, do 5 minutes of slow breathing, then put the phone away. The quality of sleep matters as much as the quantity."},
  {e:'medium',a:'mindfulness',t:['EV'],w:'out',mins:20,label:'Evening walk with presence',text:"Take a 20-minute evening walk with no audio — no podcast, no music, no calls. Just walk and notice the world around you. An evening walk with full sensory attention is one of the simplest and most effective mindfulness practices there is."},

  // Creativity extras
  {e:'low',a:'creativity',t:['EM'],w:'any',mins:10,label:'Morning creative seed',text:"Before you do anything reactive, spend 10 minutes in free creative writing or sketching — no goal, no output, no pressure. Morning creativity before input arrives is a different quality of creative thought than any other time of day."},
  {e:'medium',a:'creativity',t:['EM'],w:'any',mins:25,label:'Pre-day creative session',text:"Spend 25 minutes in creative work before email, news, or any incoming information. Morning creative sessions are protected from the day\'s accumulated cognitive load and often produce work of measurably better quality. Guard this window."},
  {e:'high',a:'creativity',t:['MD'],w:'any',mins:30,label:'Lunchtime creative sprint',text:"Spend 30 minutes of your lunch break in a creative sprint on something that matters to you. Lunchtime is an underused creative window — the day is half-done, pressure is moderate, and a creative break makes the afternoon more productive, not less."},
  {e:'depleted',a:'creativity',t:['MD'],w:'any',mins:5,label:'Midday creative doodle',text:"Take 5 minutes at midday to doodle, sketch, or write freely with zero expectation. Depleted middays still contain creative fragments worth capturing. Let the pen move without asking it to produce anything in particular."},
  {e:'low',a:'creativity',t:['NI'],w:'any',mins:10,label:'Pre-sleep creative capture',text:"Keep your notebook by your bed and spend 10 minutes at 9pm writing down any creative ideas, images, or fragments that are floating around. Then sleep on them. The hypnagogic state before sleep is one of the most creatively fertile mental conditions."},
  {e:'medium',a:'creativity',t:['EV'],w:'in',mins:35,label:'Evening craft session',text:"Dedicate 35 minutes this evening to your creative craft — write, draw, play, code, build. Evening sessions when indoors have a quality of quiet focus that daytime working hours rarely offer. Turn the evening in into creative time."},
  {e:'high',a:'creativity',t:['EV'],w:'in',mins:60,label:'Full evening creative immersion',text:"Clear the evening and spend 60 minutes in complete creative immersion — the project that excites you, worked at full depth, without distraction. High energy plus a quiet evening indoors is one of the rarest and most productive creative conditions available."},
  {e:'medium',a:'creativity',t:['NI'],w:'any',mins:10,label:'Capture and close',text:"Spend 10 minutes at 9pm capturing any creative loose ends from today — ideas, fragments, questions, things to try tomorrow — then close your creative tools and wind down. The notes capture tonight's energy for tomorrow's execution."},

  // ── Final 31 to reach 500 ────────────────────────────────────────────────
  {e:'low',a:'health',t:['MO','AF'],w:'in',mins:10,label:'Rainy day mobility',text:"Ten minutes of deliberate joint mobility work — wrists, ankles, hips, shoulders, spine — is a complete physical practice for a low-energy, indoor day. It's maintenance work that takes almost nothing from you and gives back measurably more."},
  {e:'medium',a:'health',t:['MO'],w:'in',mins:20,label:'Morning workout, bad weather',text:"Cold or wet outside this morning? Twenty minutes of indoor movement — a home HIIT circuit, a YouTube workout, or a bodyweight routine — is a full morning training session. Weather is not a variable in your capability to train."},
  {e:'medium',a:'work',t:['EV'],w:'any',mins:20,label:'Strategic thinking before sleep',text:"Spend 20 minutes this evening thinking about a bigger-picture work question — where your career is heading, what you want to build, what you've been tolerating. Evening strategic thinking, away from the day's noise, produces unusual clarity."},
  {e:'high',a:'work',t:['AF'],w:'any',mins:50,label:'Afternoon deep work',text:"Most people let high afternoon energy drift into low-value tasks and meetings. Block 50 minutes for uninterrupted deep work and protect it fiercely. The afternoon deep work session is often the most underutilised productive window in a workday."},
  {e:'low',a:'learning',t:['NI'],w:'any',mins:10,label:'Night reading ritual',text:"Read 10 minutes of something substantive before sleep every night. Consistency makes this more valuable than any individual session — it's the habit that compounds into hours of reading per month without ever feeling like a study commitment."},
  {e:'high',a:'learning',t:['EV'],w:'in',mins:40,label:'Evening intensive study',text:"High energy in the evening is rare and valuable for learning. Spend 40 minutes on the most challenging material you have. Don't waste high cognitive energy at this hour on passive review; tackle the hardest thing while you have the fuel."},
  {e:'medium',a:'relationships',t:['EM'],w:'any',mins:5,label:'Morning gratitude message',text:"Send a short, specific message of gratitude to one person before your day starts — 'I've been meaning to tell you that [specific thing] meant a lot to me.' Morning gratitude messages arrive before the recipient's day gets complicated."},
  {e:'low',a:'relationships',t:['AF'],w:'out',mins:15,label:'Walk and call',text:"Take a 15-minute walk and call someone while you do it. Low energy makes sitting down for a call feel like an effort; combining it with walking turns the call into an energising activity and removes the friction of 'I don't have the energy to call right now'."},
  {e:'high',a:'mindfulness',t:['EM'],w:'out',mins:20,label:'Morning outdoor meditation',text:"Take your meditation outside on a clear morning. Find somewhere quiet, sit or stand, and meditate for 20 minutes in fresh air and natural light. Morning outdoor meditation combines the benefits of early light, fresh air, and mindfulness practice simultaneously."},
  {e:'low',a:'creativity',t:['AF'],w:'in',mins:15,label:'Low-stakes creating',text:"Spend 15 minutes making something with zero stakes — a bad poem, a rough doodle, a joke you won't share, a melody you can't play. Low-stakes creating restores creative confidence when energy is low and the inner critic has been too loud."},
  {e:'medium',a:'creativity',t:['EM'],w:'any',mins:20,label:'Creative morning practice',text:"Twenty minutes of creative work at the start of the day, before any consumption, produces a different quality of output than at any other time. Your subconscious has been working through the night. Give it somewhere to go."},
  {e:'high',a:'health',t:['MD'],w:'out',mins:25,label:'Lunchtime outdoor run',text:"Use a 25-minute lunchtime window for a quick outdoor run in good weather. Midday running has specific benefits — the break improves afternoon performance, the sun provides vitamin D, and the outdoor air is measurably better during the day than in early morning or late evening."},
  {e:'depleted',a:'work',t:['EV'],w:'any',mins:5,label:'One tomorrow task',text:"Before you end work today, write down literally one specific task to begin tomorrow. Just one. A depleted brain can manage this. Tomorrow's you will start with a clear first step instead of spending precious morning energy deciding what to do."},
  {e:'high',a:'relationships',t:['MD'],w:'any',mins:15,label:'Lunchtime social check-in',text:"Use 15 minutes of your lunch break to call or message people you want to stay close to. Lunchtime is underused as a relationship maintenance window. Fifteen minutes of genuine check-in across 3-4 people is a meaningful investment."},
  {e:'medium',a:'learning',t:['EM'],w:'any',mins:15,label:'Morning reading before work',text:"Spend 15 minutes reading your learning material before you begin work. Starting the day with learning rather than email sets a tone for the whole day — you're building something rather than reacting to others. The 15-minute investment pays dividends all day."},
  {e:'low',a:'mindfulness',t:['MD'],w:'out',mins:10,label:'Mindful midday outside',text:"Step outside for 10 minutes at midday — phone away, just stand or sit and notice the outdoor world. This midday grounding practice reliably interrupts the cognitive compression of a busy morning and brings a quality of spaciousness to the afternoon."},
  {e:'medium',a:'health',t:['NI'],w:'any',mins:10,label:'Pre-sleep recovery sequence',text:"Spend 10 minutes before sleep on a proper recovery sequence — foam rolling any tight spots, 5 minutes of stretching, slow breathing. This nightly practice dramatically reduces next-day muscle soreness and prepares your body for the recovery that sleep provides."},
  {e:'high',a:'creativity',t:['EM'],w:'any',mins:45,label:'Sunrise creative hour',text:"Wake up 50 minutes earlier and spend 45 minutes creating at the very start of the day. The pre-dawn or sunrise hour has a unique creative quality — the world is silent, the mind is fresh, and the absence of input allows something new to emerge. It becomes a ritual quickly."},
  {e:'low',a:'work',t:['MD'],w:'any',mins:15,label:'Midday single task',text:"At midday, identify the one task that most needs completing today and spend 15 focused minutes on it before your lunch break. A midday single-task session prevents the afternoon from becoming a series of reactive responses to whatever is loudest."},
  {e:'high',a:'mindfulness',t:['MD'],w:'any',mins:15,label:'Lunchtime stillness',text:"Spend 15 minutes of your lunch break in complete stillness — sit somewhere quiet, close your eyes, and breathe. High-energy people often skip breaks. This is the practice that makes high energy sustainable rather than eventually burnout-inducing."},
  {e:'medium',a:'relationships',t:['EV'],w:'in',mins:25,label:'Rainy evening conversation',text:"A rainy evening indoors with the people you live with or care about is an invitation to a real conversation. Spend 25 minutes in genuine dialogue — no screens, no half-attention. The weather has removed every excuse to be elsewhere."},
  {e:'depleted',a:'learning',t:['EV'],w:'in',mins:5,label:'One concept, five minutes',text:"Open your notes or a learning resource and spend 5 minutes reviewing just one concept. Pick the smallest, most contained thing. Depleted evenings can still absorb one idea. That one idea, revisited consistently, becomes embedded."},
  {e:'low',a:'health',t:['NI'],w:'any',mins:8,label:'Sleep hygiene routine',text:"Spend 8 minutes on a proper sleep hygiene routine — dim the lights, put your phone in another room, cool the room down slightly, do 3 slow breaths. This consistent routine is what the research on sleep quality consistently points to as most impactful."},
  {e:'high',a:'work',t:['NI'],w:'any',mins:5,label:'Note it, then sleep',text:"If you have a great work idea at this hour, write it down in three clear sentences and put your notebook away. High-energy night work produces diminishing cognitive returns after 10pm. The idea is safer in your notebook than in a depleted decision-making session."},
  {e:'medium',a:'mindfulness',t:['EM'],w:'in',mins:15,label:'Rainy morning sit',text:"A rainy morning is one of the most naturally conducive meditation environments available — the sound of rain, the permission to stay inside, the softness of early morning light. Spend 15 minutes in a relaxed, unhurried meditation practice."},
  {e:'low',a:'creativity',t:['MD'],w:'any',mins:10,label:'Midday creative reset',text:"Spend 10 minutes away from productive work at midday and just create something small — a sketch, a sentence, a short melody. The creative detour at midday often produces the afternoon's best analytical ideas by letting the brain shift gears fully."},
  {e:'high',a:'learning',t:['AF'],w:'any',mins:35,label:'Afternoon mastery session',text:"Block 35 minutes of afternoon time for deliberate practice at the most challenging level you can sustain. High energy in the afternoon is less common than in the morning — if you have it, use it for the hardest learning you have rather than passive review."},
  {e:'depleted',a:'relationships',t:['EV'],w:'in',mins:3,label:'Indoor warm gesture',text:"From wherever you are right now, send one genuine, specific message to one person who matters. 'I saw something today that made me think of you' is enough. Small warm gestures from indoors on quiet evenings are often the ones people remember longest."},
  {e:'medium',a:'health',t:['EV'],w:'out',mins:20,label:'After-dinner walk',text:"Go for a 20-minute walk after dinner on a pleasant evening. Post-meal walking is one of the most evidence-backed metabolic health practices — it reduces blood sugar spikes, improves digestion, and consistently improves sleep quality that night."},
  {e:'high',a:'mindfulness',t:['AF'],w:'any',mins:35,label:'Deep afternoon meditation',text:"Afternoon meditation at high energy produces a distinct quality of awareness — alert but anchored. Spend 35 minutes in a focused practice, using the natural brightness of your mind to go deeper than early morning or evening sessions typically allow."},
  {e:'low',a:'work',t:['EV'],w:'in',mins:10,label:'Cosy evening planning',text:"On a rainy or cold evening, spend 10 minutes planning tomorrow with a warm drink and no pressure. Evening planning when indoors is more comfortable and less anxious than morning scrambling. The plan itself is simple — just tomorrow's three priorities."},
];
